-- Seed: 263 øvelser fra v1 katalog
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ktc4qjmenu', 'Ståtrold', 'En spiller er ''trold'' og forsøger at røre de andre. Bliver man ramt, skal man stå stille med benene spredt (som en stråmand), indtil en fri spiller kravler igennem benene og befrier en. Træner reaktion og rumlig opmærksomhed.', 'hal', NULL, '["opvarmning","leg"]', '["U9","U11"]', 0, 'Fungerer også godt hvor man befris med en tackling af en spiller der kommer i fuld fart', NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('obwheydmpr', 'Katten, musen og plankeværket', 'Katten skal fange musen, men musen kan gemme sig bag et ''plankeværk'' af 1-3 spillere der holder hinanden i hånden. Træner afskæring og spatial bevidsthed.', 'hal', NULL, '["opvarmning","leg"]', '["U9","U11"]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('stonj8g0aw', 'Cirkelbeskyttelse', 'Hold af 4-5 spillere. Fire spillere står i cirkel hånd i hånd og beskytter en navngiven spiller  i cirklen. En 5. spiller udenfor forsøger at røre den navngivne  spiller. Cirkelholdet drejer rundt for at beskytte. Træner koordination og forsvarspositionering.', 'hal', NULL, '["opvarmning","leg"]', '[]', 0, NULL, 'https://issuu.com/dhf_publikationer/docs/tr_ningsprogram_u11_uge_33_1_dd6f883722e78b', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('bvztytxode', 'Kædetik', 'En spiller er fanger. Når nogen fanges, tager de hinanden i hånden og jagter de resterende spillere som en kæde. Kæden vokser for hvert fang. Kun yderste spillere i kæden kan fange. Træner samarbejde og rumopfattelse.', 'hal', NULL, '["opvarmning","leg"]', '["U9","U11"]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('8xj98zuy70', 'Haleleg', 'Alle spillere stikker en vest ned i bukserne bag på som en hale. Alle forsøger at stjæle hinandens haler, mens de beskytter deres egen. Den der samler flest haler vinder. Træner motorik, balance og reaktionshurtighed.', 'hal', NULL, '["opvarmning","leg"]', '["U9","U11"]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('dn5pkzwl1b', 'Beskyt din makker', 'I Trio/kvartet: Spiller 1 holder fat i spiller 2 bagfra (ved hoften). En fanger forsøger at røre spiller 2''s mave. Spiller 1 skal dreje og bevæge sig for at beskytte sin makker. Træner bevægelighed og kropsbevidsthed.', 'hal', NULL, '["opvarmning","leg"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('xi4bqzjk79', 'Stoledans med veste eller bolde', 'Klassisk stoledans: Der er én bold/vest færre end spillere. Når træner fløjter, skal alle gribe en bold/vest. Den uden sidder ud. Fortsæt til én vinder. Træner reaktion og eksplosiv bevægelse.', 'hal', NULL, '["opvarmning","leg"]', '["U9","U11"]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('96lfpj7g8d', 'Smittespredning', 'En starter med en bunke veste. Når hun rører en anden spiller, får denne nogle veste og hjælper med at fange. ''Smitten'' spreder sig til alle er fanget. Træner rumopfattelse og samarbejde.', 'hal', NULL, '["opvarmning","leg"]', '["U9","U11"]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ken8kdirey', 'Fange ved sammenspil', '2 spillere skal fange en 3. spiller ved at aflevere bolden til hinanden og røre forfølgeren med bolden. Man må drible og afleverer. Træner afleveringstiming og positionsspil.', 'hal', NULL, '["opvarmning","leg"]', '["U9","U11"]', 0, 'Finsk partibold er en variant, på et mindre område men med flere spillere. Knap så meget løben, men mere bold og sammenspil', NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('rtnc6s3pm2', 'Høvdingebold', 'To hold. En høvding fra hvert hold står bag modstandernes baglinje. Spillere på banen forsøger at kaste bolden til deres høvding uden at modstanderne opfanger den. Fanges bolden af høvdingen, skifter den pågældende til høvdingens side. Når kun høvdingen er tilbage, skal denne gå over på egen banehalvdel, og har kun 1 liv.  Træner kastpræcision og samarbejde.', 'hal', NULL, '["opvarmning","leg"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('7u9y78u2kg', 'Hent keglen', 'To hold på tværs af banen. Hvert spiller får et nummer. Når træner råber et nummer, løber de to spillere med det nummer ud og forsøger at hente en kegle i midten og bringe den hjem uden at blive rørt. Træner sprintreakton og konkurrenceevne.', 'hal', NULL, '["opvarmning","leg"]', '[]', 5, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('r9q5nuqvvo', 'Murtik', 'En spiller er fanger og forsøger at røre de andre. Man er i sikkerhed ved at røre en væg/mur. Der kan kun stå én spiller ved en væg ad gangen. Ny fanger vælges løbende. Træner rumlig bevidsthed og eksplosiv bevægelse.', 'hal', NULL, '["opvarmning","leg"]', '["U9","U11"]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('i2k03lhfe0', 'Kampen mod bolden', '6-8 spillere i cirkel. En spiller sætter en aflevering i gang rundt i cirklen. En midterspiller forsøger at afbryde. Sætter midterspilleren sig på bolden, skifter den der lavede fejlen til midten. Træner afleveringspræcision under pres.', 'hal', NULL, '["opvarmning","leg"]', '["U9","U11"]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('x767b4vlb9', '3 på stribe', 'Matrix med 9 kegler i 3x3 gitter. To hold á 3 spillere, hvert hold har 3 veste af samme farve. Hold løber skiftevis ud og placerer en vest på en kegle. Første hold der får 3 i træk (vandret, lodret eller diagonalt) vinder. Lav evt øvelser på vej ud til matrix, fx hulahopring, hop over bænke eller lignende Træner taktisk tænkning og sprint.', 'hal', NULL, '["opvarmning","leg"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('pvg9iz4nrd', 'Memory', 'Kortsæt med par lægges på gulvet med bagsiden opad. To hold løber i stafet ud og vender to kort ad gangen. Par tages hjem. Holdet med flest par vinder. Træner koncentration, hukommelse og stafetdisciplin.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('uc91ygaark', 'Behændigsdyst i cirkel', 'Parvist i cirkel omkring en bunke bolde/veste. Træner fløjter – alle løber ud og forsøger at hente en bold/vest. Der er én færre end par, så ét par står tomhændet. Træner reaktion og eksplosiv bevægelse.', 'hal', NULL, '["opvarmning","stafet","leg"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('wn2vmetyr0', 'Fange med liggende helle', 'En spiller er fanger. Man er i sikkerhed (helle) ved at ligge ned på siden ved siden af en anden spiller. Der kan kun ligge én ved siden af en anden. Fanger skiftes løbende. Træner koordination og rumforståelse.', 'hal', NULL, '["opvarmning","leg"]', '["U9","U11"]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('7kbi4devmy', 'Partibold', 'To hold i afgrænset område. 10 afleveringer i træk giver et point. Modstanderne forsøger at afbryde. Ingen dribling. Træner afleveringstiming og positionering uden bold. En god variant er hvor man ikke må stå spille med bolden', 'hal', NULL, '["opvarmning","småspil"]', '[]', 5, 'Lav den evt med en navngiven direkte modstander', NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('pshmcudiga', 'Partibold med fart', 'Samme som partibold, men spillerne skal runde en af banemarkeringskeglerne hver gang de har rørt bolden. Der gives point for 10 afleveringer i træk. Træner sammenspil under bevægelse og beslutningshastighed.', 'hal', NULL, '["opvarmning","småspil"]', '[]', 5, NULL, NULL, 10, 'exercises/pshmcudiga.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('bkrmlqo48z', 'Baglinjebold', 'To hold. Man scorer ved at lægge bolden ned på modstandernes baglinje. Ingen dribling, kun afleveringer. Forsvar forsøger at afbryde. Træner positionsspil og sammenspil.', 'hal', NULL, '["opvarmning","småspil"]', '[]', 5, 'Tilføj at man får 5 englehop/armbøjninger hvis man røres af boldholder. Dette gør at man forsvarere forsøger at bryde afleveringer, i stedet for at mandsopdække. Og det skaber overtal', NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('hcg8w3s6pk', 'Partibold med midterfelt', 'Tre zoner på tværs af banen To hold, hvor halvdelen af hvert hold er fordelt i de to yderste zoner. Den midterste zone er ikke farbar. Scorer ved succesfuld tværaflevering. Træner præcision og timing under pres.', 'hal', NULL, '["opvarmning","småspil"]', '[]', 4, NULL, 'https://traenerguiden.dgi.dk/guide/haandbold/exercises-overview/Alle%20%C3%B8velser%20-%20haandbold/1d324e3a-a4c8-4ff8-a545-aac6b8dcad0e', 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('y5qoalanbi', 'Partibold med scoring i kegleport', 'Sæt  kegleporte op per hold (1-2 mere end spiller per hold). Der scores ved at aflevere bolden igennem en kegleport til en holdkammerat. Ingen dribling. Træner overblik, sammenspil og beslutning om hvornår porten er fri.', 'hal', NULL, '["opvarmning","småspil"]', '[]', 4, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('y49yy2grby', '360 grader partibold', 'Hold af 2 eller 3: Man scorer ved atl røre en kegle med bolden. Der må ikke dribles, men keglen kan angribes 360 grader rundt. (bevælgelse, forsvar skal tage højde)', 'hal', NULL, '["opvarmning","småspil"]', '[]', 4, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('y2elddmvr5', 'Touch-rugby', 'Score ved at løbe bag modstandernes baglinje med bolden. Røres man med bolden i hånden, skal man straks aflevere. Bolden skal altid passes bagud eller sidelæns. Træner hurtig aflevering under pres og retningsskift.', 'hal', NULL, '["opvarmning","småspil"]', '[]', 3, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('rxxioowqaa', 'Feltspil', 'To hold. Scoring ved at lægge bolden ned i modstandernes målfelt (markeret med kegler). Bolden afleveres til holdkammerater i feltet. Ingen keeper. Træner boldcirkulation og angrebsopbygning.', 'hal', NULL, '["opvarmning","småspil"]', '[]', 3, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('tt2pk0f511', '1 mod 1 med tilspiller', '1 mod 1 på halv badmintonbane. En fast tilspiller på siden sætter spillet i gang. Angriber forsøger at score på lille mål, forsvarer forsøger at afbryde. Vekslende roller. Træner 1 mod 1-teknik, finter og forsvarsstilling.', 'hal', NULL, '["opvarmning","småspil"]', '[]', 0, 'Kræver meget overvågning', NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('to1k35haga', 'Smørklat', '3 spillere sidder på numsen på gulvet, 1 spiller (smørklat) står og jagter bolden. De siddende afleverer bolden rundt og smørklat forsøger at afbryde. Fanges bolden, skifter den der lavede fejlen til at stå. Træner afleveringspræcision og reaktion.', 'hal', NULL, '["opvarmning","småspil"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('akcdf25t1w', 'Kegletårn', 'Sæt en spids kegle balanceret på en skummadras. 2 hold á 4 scorer ved at slå tårnet ned med bolden, mens det andet hold forsvarer. Ingen kontakt med spillere. Træner kastpræcision og forsvarstaktik.', 'hal', NULL, '["opvarmning","småspil"]', '[]', 4, 'Den rette strategi for forsvar er at gå højt på boldholder, og lade de andre forsvarer stå tæt om keglen. Lidt 3-2-1 agtigt.', NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('u3ukbs29p7', 'Touchdown', 'Ca. 4 mod 4 med en stor madras midt på banen. Man scorer ved at lande på madrassen med bolden (hoppe ned på den). Modstanderne forsvarer madrassen. Træner sammenspil, beslutning og boldkontrol i luften.', 'hal', NULL, '["opvarmning","småspil"]', '[]', 4, 'Den rette strategi for forsvar er at gå højt så angriberne ikke kan nå ind til madrassen med 3 skridt', NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('2f5vg6uao0', 'Pingvinhop', 'Stafetøvelse: Klem en bold fast mellem knæene og hop fremad som en pingvin. Slip ikke bolden. Hop til markering og tilbage, aflevér til næste. Træner koordination og balance.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, 'https://www.instagram.com/reel/DSDcSTjDHpr/?igsh=aHdienUyZTZpcWdw', 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('hhg01m5ezt', 'Krabbegang', 'Stafetøvelse: Gå på alle fire med maven opad (krabbestilling) frem og tilbage til markering. Hænderne og fødderne i gulvet, hoften hævet. Træner arm- og skuldersstyrke samt kropsbevidsthed.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, 'Forlæns og baglæns', NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('azbq6jfksy', 'Bearwalk', 'Stafetøvelse: Gå på alle fire med maven nedad – hænderne og tæerne i gulvet, knæene løftede. Frem til markering og tilbage. Træner skulder-, arm- og corestyrke.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 4, 'Forlæns og baglæns', NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('mv4v5dxa41', 'Møve op numsen', 'Stafetøvelse: Rul frem på gulvet, men numsen skal konstant røre gulvet. Skub med benene og hænderne. Frem til markering og tilbage. Træner kropsbevidsthed og koordination.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('zp6lcbx79e', 'Frøhop', 'Stafetøvelse: Hop frem som en frø – begge håndflader skal røre gulvet mellem hvert hop. Sæt af med benene og land blødt. Frem til markering og tilbage. Træner explosivitet og koordination.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('19gw220nha', 'Almindelig dribling', 'Stafetøvelse: Drible bolden frem til markering og tilbage med grundlæggende dribleteknik. Skift hænder undervejs. Træner grundlæggende boldkontrol og dribleteknik.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, 'Forlæns og baglæns. Med højre og venstre', NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('psfllb06g8', 'Drible med to bolde', 'Stafetøvelse: Drible to bolde samtidigt, en i hver hånd, frem og tilbage. Koordinér begge hænder. Kræver god rytme og koncentration. Træner ambidekstri og koordination.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('t66mhdml7n', 'Dribling med bold ved fod', 'Stafetøvelse: Drible en bold med hænderne, mens en anden bold holdes i balance på foden/vristen. Frem og tilbage. Meget udfordrende koordinationsøvelse for motorik og balance.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('z46ryjwsav', 'Sprint, ned og ligge på x farvede linjer', 'Stafetøvelse: Sprint frem og kast dig ned og lig fladt på en bestemt farvet linje, som træner udråber. Rejs dig og sprint videre. Træner reaktion på signal og eksplosiv bevægelse.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('uvko42mbdb', 'Sprint, vend om når træner fløjter', 'Stafetøvelse: Sprint frem, og ved trænerfløjt vender man lynhurtigt og løber den anden vej. Fløjtes igen, vend igen. Træner retningsskift og reaktion.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('opjdyymsmj', 'Sprint fra liggende', 'Stafetøvelse: Start liggende på maven med hænderne ved siden af kroppen. På signal sprinter man op og løber til markering. Træner eksplosivt oprejsning og reaktionstid.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('cdyreyueso', 'Forfølgesløb', 'Forfølgelsesløb a la seksdagesløb på keglebane (2-3 på hvert hold). En sprinter ad gangen indtil holdkammerat er nået, hvorved holdkammerat overtager sprinten. De der ikke sprinter dribler med bold', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('26nxsaj3ml', 'Bowling', 'Stafetøvelse: Hvert hold løber ud til en keglemarkering og kaster/ruller en bold for at vælte en opstilling af kegler. Hvert hold tæller point for væltede kegler. Træner præcision og kastekraft.', 'hal', NULL, '["opvarmning","stafet","leg"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('55jceqdm2r', 'Diamant', 'Stafetøvelse: Fire kegler opstillet i diamantform. Sprint frem og rør alle fire kegler i rækkefølge. Fungerer godt til at træne retningsskift og acceleration. Kan laves med eller uden bold.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('8mk5bdjqy4', 'Kålorm', 'Stafetøvelse: Spillere på hvert hold står på række. Den bagerste dribler frem igennem rækken (zigzag), sætter sig forrest og afleverer bolden bagtil. Næste gør det samme. Træner dribling i tætte rum og overblik.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, 'Vvariant: Bagerste skal løbe over rækken, og bowle tilbage. Tredje variant: løb op foran og bowl bolden under rækken i udgangsstilling', NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('50dxli0igv', 'Stafet med depeche', 'Hold af 3-4. Brug en vest som stafetpind (depeche). Spillerne løber stafet – en ad gangen – overrækker vesten til næste. Kan varieres med forhindringer eller dribbling. Træner sprint og holdspirit.', 'hal', NULL, '["opvarmning","stafet"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('8pomtp8v0w', 'Aben i træet', 'I par: Spiller 1 (aben) kravler hele vejen rundt om spiller 2 (træet), der står stille med spredte ben. Spiller 2 drejer kroppen for at gøre det sværere. Træner bevægelighed, kropsbevidsthed og lidt styrke.', 'hal', NULL, '["opvarmning","styrke","leg"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('6c1p38q1pr', 'Søstjernen', 'En spiller (søstjernen) ligge fladt på gulvet med udstrakte arme og ben. De andre spillere forsøger at vende søstjernen om. Søstjernen skal holde sig så stiv og tung som muligt. Træner core-styrke og kropsspænding.', 'hal', NULL, '["opvarmning","styrke","leg"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('de24uba1zi', 'Sumokamp', '2 og 2 i afmærket ring. Skub modstanderen ud af ringen med kroppen. Man kan starte stående, på knæ eller i squat. Ingen gribning af tøj. Træner eksplosiv styrke, balance og kropskontakt.', 'hal', NULL, '["opvarmning","styrke","tvekamp"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('p2zxzvptyp', 'Trillebør', '2 og 2: Spiller 1 går på hænderne mens spiller 2 holder ankled oppe. Gå fremad på hænderne til markering og skift. Klassisk styrkeøvelse der træner arm-, skulder- og corestyrke.', 'hal', NULL, '["styrke"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('aqrp1l1gsr', 'Spejlet / Juke out', '2 mod 2 med to kegler. Angriber skal runde en af de to kegler, forsvarer forsøger at aflæse retningen og røre angriberen. Angriber arbejder med fintebevægelse og retningsskift. Træner 1v1-finter og forsvarslæsning.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '[]', 0, NULL, 'https://www.facebook.com/share/r/eyugB1Tej3zKw9iD/?mibextid=WC7FNe', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('73oaz44i60', 'Rør din makker så mange gange som muligt', '2 og 2. Den ene forsøger at røre den andens skuldre/arme så mange gange som muligt på 20-30 sekunder. Den anden undviger. Skift roller. Træner reaktion, smidighed og eksplosiv armbevægelse.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '["U9","U11"]', 0, 'Variant: Den ene skal drible i 15 sekunder uden den anden slår bolden væk', NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('6ghf3ilw2h', 'Følg din makker med dribling', '2 og 2 med en bold hver. Spiller 1 løber tilfældige retninger, spiller 2 skal følge tæt med dribling. Herefter skifter leder/følger. Træner dribling med blik oppe og reaktion på makkers bevægelse.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '["U9","U11"]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('400pjktikv', 'Forsvar bolden', '2 og 2: En bold ligger på gulvet. Spiller 1 forsvarer bolden, spiller 2 forsøger at røre den. Ingen kontakt med modstander. Skift roller. Træner forsvarsstilling og lavt tyngdepunkt.', 'hal', NULL, '["opvarmning","tvekamp","styrke"]', '[]', 0, 'Varier afstand til bolden, afstand mellem spillerne. Start siddende, liggende', NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ndd117gv9m', 'Hånd i hånd dyst', '2 og 2: De holder hinanden i én hånd. Spiller 1 dribler med den frie hånd, spiller 2 forsøger at slå bolden væk. Dribler skifter hånd, forsøger at beskytte bolden. Træner boldkontrol under modstand.', 'hal', NULL, '["opvarmning","tvekamp","styrke"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('chcbbpmldd', 'Slå den andens bold væk', '2 og 2 med en bold hver, hånd i hånd. Begge dribler og forsøger at slå hinandens bold ud af hænder/zone, mens de beskytter deres egen. Sidst med bold vinder. Træner boldkontrol og perifert overblik.', 'hal', NULL, '["opvarmning","tvekamp","styrke"]', '[]', 0, 'Variant: Giv folk en vest som hale, som de også skal passe på', NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('yakjb2y858', 'Sten-saks-papir', '2 og 2: Brug hele kroppen til at lave sten (sammenkrøl), saks (arme og ben ud til siden) og papir (stå med spredte arme). Tæl 1-2-3 og vis figuren. Vinder tager et skridt frem, taber et tilbage. Eksplosiv leg der træner reaktion.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '[]', 0, 'Variant: lige og ulige', NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('cjqirdv09l', 'Stik af med bolden', 'Variation af sten-saks-papir: I stedet kaster én spiller bolden til den anden på 1-2-3. Vinder sprinter efter bolden, taber forsøger at afbryde inden vinder fanger. Træner reaktion og eksplosivt sprint.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('uucin65hz5', 'Stik af med objektet', '2 og 2 (evt. 3): En bold, kegle, vest eller sko placeres i midten. På signal forsøger begge at gribe objektet og stikke af. Den der griber, forsøger at nå en markering, den anden forsøger at afbryde. Træner reaktion og 1v1-duel.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('d97iqv3hgq', 'Dozy Doe', '2 og 2: Stå på et ben med armene krydset over brystet. Forsøg at få modstander til at miste balancen ved at skubbe/dytte med kroppen. Første der sætter andet ben i gulvet taber. Træner balance og stabilitet.', 'hal', NULL, '["opvarmning","tvekamp","styrke"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('rk151jue04', 'Sid på hug', '2 og 2: Begge sidder i squat/hug-stilling. Forsøg at få den anden til at miste balancen og falde bagud eller sætte sig. Ingen gribning. Træner benstyrke og balance.', 'hal', NULL, '["opvarmning","tvekamp","styrke"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('gstp6nzawq', 'Hurtige fødder', '2 og 2: Hold hinanden i hænderne. Forsøg at træde på den andens fødder uden selv at blive trådt på. Meget hurtigt benbevægelse. Træner fodarbejde og reaktionshastighed.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('i6h3dne1yi', 'Klap på lår', '2 og 2: Hold hinanden i hænderne. Forsøg at klap den andens lår med hånden, mens du undviger klap på dit eget lår. Træner hurtig armbevægelse og reaktion.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('2t4p86is4o', 'Klap over hånd', '2 og 2: Lig overfor hinanden på alle fire. Forsøg at klap den andens hånd, mens du trækker din egen væk. Lynhurtig reaktionsøvelse der træner håndreflekser og koncentration.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('7jd9j708t6', 'Træk hinanden', '2 og 2: Spiller 1 holder armene om spiller 2 bagfra. Spiller 1 forsøger at trække spiller 2 bagover en markering, mens spiller 2 modstår. Skift roller. Træner styrke, balance og kropsposition.', 'hal', NULL, '["opvarmning","tvekamp","styrke"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('sf1gh7b5nu', 'Forsvarsbevægelsesbane med makker', '2 og 2: Spiller bevæger sig sidevejs og fremad langs kegler i defensiv stil (lavt tyngdepunkt, sidelæns). Makker spejler bevægelsen på modsat side. Kan laves med bold som tilspil. Træner forsvarspositionering og bevægelighed.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '["U9","U11"]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('2l6iflxca4', 'Stregspillerøvelsen', '2 og 2: En bold ligger på gulvet. Spiller 1 (forsvarer) forsøger at nå bolden. Spiller 2 (streg) bruger kroppen til at blokere og holde forsvaren væk. Ingen gribning. Træner fysisk kamp om position ved stregspil.', 'hal', NULL, '["opvarmning","tvekamp","styrke"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('nfnkwzkjus', 'Stregspillerøvelsen med indstik', '3 spillere: Samme som stregspillerøvelsen, men nu er der en tilspiller (3. spiller) der afleverer bolden til stregspilleren, når hun har positioneret sig, så hun kan lægge den på keglen. Forsvar skal blokere indstikket. Træner timing og samspil ved streg.', 'hal', NULL, '["opvarmning","tvekamp","styrke"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('1qtfob8d1y', 'Rør bjørnens fødder', '2 og 2: Spiller 1 er på alle fire (bearwalk-stilling). Spiller 2 forsøger at røre spillerens fødder/ankler, mens spiller 1 trækker dem væk. Tidsbegrænset. Træner hurtige fødder og kropsbevidsthed.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('zz517x7ydk', 'Parvis haleleg', '2 og 2: Spiller 1 har en vest i bukserne bagtil som hale. Spiller 2 forsøger at stjæle halen, spiller 1 undviger. Tidssat – tæl hvor mange gange halen stjæles. Skift roller. Træner undvigebevægelse og reaktion.', 'hal', NULL, '["opvarmning","tvekamp","hurtighed"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('yot627dia3', 'Opvarmning af arm', 'Parvist kast frem og tilbage for at varme arme og skuldre op. Start tæt og øg gradvist afstand. Fokus på korrekt kasteteknik: rotér skulder, stræk armen fuldt ud og følg igennem. Grundlæggende men vigtigt for at undgå skader.', 'hal', NULL, '["aflevering"]', '[]', 0, 'Træd frem i kastet, lange, hopskud, sidelæns, kig væk, bagom ryggen, een hånd,  høj arm, knæk, mellem benene, studs, hop med vip, 3 skridt, sidde ned, sidde på knæ, forkerte hånd, samlede ben', NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ciahryat3r', 'Aflevering efter skudfinter', '2 og 2: Lav en skudfinter inden du afleverer til makker. Øv klemmet/klembevægelsen som optakt til aflevering. Træner timing og fintebevægelse ved aflevering.', 'hal', NULL, '["aflevering"]', '[]', 4, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('qvvcqn77wa', 'Aflevering med forspænding', 'Højrehåndede: Stå på etben (højre) med bold og høj arm. Tag et stort skridt frem og aflevér med fuld armbevægelse. Træner forspænding i overkroppen og eksplosiv aflevering.', 'hal', NULL, '["aflevering"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('n3ddr5503q', 'Afleveringer med tyveri', '2 og 2: Aflevér frem og tilbage, men forsøg at stjæle den andens bold mens du selv afleverer. Kun stående fødder – ingen bevægelse. Træner afleveringstiming, boldkontrol og perifert fokus.', 'hal', NULL, '["aflevering"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('28hprtor9c', 'Sidelæns stempel', '2 eller 3 og 3: Sidelæns afleveringer med stempelbevægelse – fod frem i retning af aflevering, arm udstrakt. Fokus på korrekt afsætning og stempling. Grundlæggende afleveringsteknik der træner bredde i spillet.', 'hal', NULL, '["aflevering"]', '[]', 4, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('vkjesd2ki6', 'V bevægelse', '2 og 2: En spiller arbejder i V-bevægelse om en kegle. Den anden er fast tilspiller. Husk at skifte sid. Træner tilbageløb, timing og modtagelse i fart.', 'hal', NULL, '["aflevering"]', '[]', 5, NULL, 'https://traenerguiden.dgi.dk/guide/haandbold/exercises-overview/Alle%20%C3%B8velser%20-%20haandbold/73c377ed-46c0-4323-84a2-b4dea3fa5b69', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('fuwwd6d0rd', 'Aflevering efterfulgt af tackling', '2 eller 3 og 3: Angriber aflevererer og forsøger derefter at nappe bolden tilbage (tackling). Fokus på armstilling ved tackling og at angriberen hopper for at undgå tacklingen. Træner forsvarsteknik og boldholderens reaktion.', 'hal', NULL, '["aflevering"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('8vqlfqifnq', 'Siddende afleveringer', 'Sid med bagen i gulvet, ben i luften (kun bagen rører gulvet). Aflevér til makker frontalt og fra siden. Kræver god balance og core-styrke. Træner overkroppens rotatiosstyrke og afleveringsteknik isoleret.', 'hal', NULL, '["aflevering"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ukugxvw4yv', 'Afleveringer fra sidelinje til sidelinje (baglæns udfordring)', '2 og 2: Fra sidelinje til sidelinje – den ene løber på tværs af banen og modtager, afleverer retur, løber tilbage. Den anden er fast. Træner afleveringspræcision til en spiller i bevægelse og timingforståelse.', 'hal', NULL, '["aflevering"]', '[]', 0, NULL, NULL, 5, 'exercises/ukugxvw4yv.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('0vbigz0kmv', 'Afleveringer 3 og 3', '3 mod 3: Øv specifikke afleveringsmønstre: Centerkryds (AK), presstempel, fransk kryds / jugo. Fokus på korrekt teknik og timing i de tre grundlæggende mønstre', 'hal', NULL, '["aflevering"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('Afleveringer med finter', 'Afleveringer med finter', '3 og 3; 3 skridtsfinter med hopskuds aflevering - spilleren i midten er passiv. Spiller der finter bliver derefter den passive forsvar. Lav derefter med skudfinter venstre om. TIl sidst med fuld forsvar Øver fintens effekt og afleveringstiming under defensivt pres.', 'hal', NULL, '["aflevering","finter"]', '[]', 3, NULL, NULL, 5, 'exercises/Afleveringer_med_finter.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('9kj225tnxy', 'Aflevering med puls', '3 og 3 med to bolde: Løb over til den anden side og modtag bolden, aflevér straks tilbage og løb retur. Højt tempo – skift hurtigt. Træner afleveringshurtighed og kondition.', 'hal', NULL, '["aflevering"]', '[]', 2, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('bh5p3jvdj9', 'Aflevering med løb', '3 og 3 med to bolde: Midtermanden runder de to yderste og laver afleveringer undervejs. Konstant bevægelse. Træner boldhåndtering i fart og kommunikation.', 'hal', NULL, '["aflevering"]', '[]', 2, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('npby7bkdk1', 'Aflveringer back-center-back', 'Øvelse med back-midt-back positioner. Fokus på: stempel (pressing movement), tilbageløb og timing. Backsene skifter i pres og retur. Grundlæggende angrebsmønster for backs.', 'hal', NULL, '["aflevering"]', '[]', 0, NULL, 'https://traenerguiden.dgi.dk/guide/haandbold/exercises-overview/Alle%20%C3%B8velser%20-%20haandbold/074512c0-6f20-4514-85c7-9c53cfc673f2', 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('awgbx4e3j6', 'Afleveringer i fart', '2 eller 3 og 3: Afleveringer op ad fuldbane med afslutning. Fokus på tempo og timing. Alle løber fremad, bolden afleveres i fart. Simulerer angrebssituation på fuld hastighed.', 'hal', NULL, '["aflevering"]', '[]', 4, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('wlxwy3yelz', 'Aflevering til spiller i fart', '3 og 3: Backs runder en kegle og frigør sig. Første til at runde er angriber. Tilspiller skal levere bolden præcist til den frikørte spiller i fart. Træner timing og præcision til bevægende modtager.', 'hal', NULL, '["aflevering"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('gxdpdbb7fh', '2 og 2 op ad banen', '2 og 2 op ad banen i begge retninger med let afslutning. Fokus på tempoafleveringer i fart. Begge spillere løber paralelt og afleverer skiftevis. Afsluttes med skud på mål. Grundlæggende kontraøvelse.', 'hal', NULL, '["aflevering","hurtighed"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('hwk5zy6zmh', '2 og 2 op ad banen indvendigt', '2 og 2 op igennem midten af banen med hurtige afleveringer. Begge spillere holder sig i det smalle midterrum og afleverer i højt tempo. Kræver præcision og timing. Parret løber retur i hver sin side udvendigt og laver lange afleveringer over midten. Træner samspil i det centrale rum.', 'hal', NULL, '["aflevering","hurtighed"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('qnn7v3xbz7', 'Fløjraket', '2 og 2: Start ved midterlinje. Fløj starter med bold, afleverer til back, og løber op mod mål i høj fart. Back kan tage 1-2 skridt og laver en præcis aflevering til fløj som uden at sænke fart afslutter', 'hal', NULL, '["aflevering","hurtighed","skud"]', '[]', 4, NULL, NULL, 15, 'exercises/qnn7v3xbz7.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('w3nvsq8opz', 'Backraket', '2 og 2 på smalle backs. Back 1 sætter bolden i gang med et kast til tilspliller og løber op ad banen i høj fart. Back 2 modtager bolden, og laver en præcis aflevering til back 1 der afslutter i høj fart. Fokus på backens angrebsbevægelse og afleveringstiming i høj fart.', 'hal', NULL, '["aflevering","hurtighed","skud"]', '[]', 5, 'variation med en forsvarsspiller eller 2x Georg at skude over', NULL, 15, 'exercises/w3nvsq8opz.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('vjnq6r7teq', 'Skud fra siddestilling', 'Sid på bænk med bold i skudarm. Rejs dig op, tag 1 skridt og lav et hopskud over en evt. pude eller plasticmand. Fokus på eksplosivt afsæt fra siddende. Styrker benene og øver samspillet mellem afsæt og kasteteknik.', 'hal', NULL, '["skud","styrke"]', '[]', 4, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('lgpbjq8zbq', 'Duel på buen', '1 mod 1 på buen. Angriber og forsvarer starter overfor hinanden, forsvar med bolden. De to spillrer roterer om hinanden, og angriber modtager bolden og forsøger gennembrud med afslutning – forsvarer tackler. Roller byttes: afslutter går i forsvar, forsvar bliver tilspiller. Træner duelteknik, mod og forsvarstiming.', 'hal', NULL, '["finter","duel"]', '[]', 3, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('finterr i åben ramme', 'finter i åben ramme', '1 mod 1 i afgrænset rum med tilspil og skud. Angriber skal via finter vinde en friposition og afslutte. Forsvar reagerer på finterens retning. Grundlæggende 1v1-situation der træner fintebevægelse og målafslutning.', 'hal', NULL, '[]', '[]', 4, NULL, NULL, 15, 'exercises/finterr_i_aben_ramme.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('finter i åben ramme med skrå tilgang', 'finter i åben ramme med skrå tilgang', 'Øv fintebevægelse med skrå angrebsvinkel. Starten uden forsvar for at øve selve bevægelsen korrekt, derefter 1 mod 1. God til at lære at gå bagom forsvaret med skrå approach og efterfølgende skud.', 'hal', NULL, '[]', '[]', 4, NULL, NULL, 15, 'exercises/finter_i_aben_ramme_med_skra_tilgang.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('crxb9np2ez', 'finterbane', 'Stil kegler langs sidelinjen med jævne mellemrum. Spillerne løber banen og laver en valgt fintebevægelse ved hver kegle. Kan kombineres med afslutning til sidst. Øver fintebevægelse gentagne gange i fart.', 'hal', NULL, '["finter","duel"]', '[]', 0, 'Variant, lad dem gå den anden vej som i video', 'https://www.facebook.com/share/r/1Vzo6vkuD7/?mibextid=wwXIfr', 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('s4w3k1ubvl', 'Duelspil efter undergang', 'Back laver en undergang efter spil til fløj, dvs løner under midtspiller, som til gengæld løber back om back og angriber forsvarsback i høj fart på fløjaflevering. Derfra udfordrer backen en forsvarer i 1v1. Fokus på overgangen fra underkørsel til aktiv duelstilling.', 'hal', NULL, '["finter","duel"]', '[]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('m9apd655v0', 'fintervarianter i keglefelt', 'Spillere øver fintebevægelser i en opstillet keglefirkant (overslag, 1. divisions-finte, hopskudsfinte) med efterfølgende afslutning. Kan starte fra nedhop fra bænk, hopspring eller afsæt fra gulv. Variér afsættype for at øve alle situationer.', 'hal', NULL, '["finter","duel"]', '[]', 4, 'Vaiant: Skud fra samlet når man lander (aka fremfaldsskud). Variant to: først den ene vej, så den anden (dobbeltfinter)', 'https://www.instagram.com/p/DPpOMtKCBrD/?img_index=1', 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('b964q0cygh', 'Vending i keglefelt - stregspil', 'Keglefelt med stregspillervariant med ryggen til mål. Modtag tilspil fra næste spiller, vend med bolden og skyd. Fokus på vendeteknik, kroppen som skjold og eksplosivt afsæt. Træner stregspillets grundelementer.', 'hal', NULL, '["finter","duel"]', '[]', 5, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('y69a0s9fny', 'Afvisning', '1 mod 1 med tilspil eller fra dribling. Forsvar skal afvise/blokere med armene. Fokus på korrekt armstilling ved afvisning: armene strakte nedad-fremad, møde bolden aktivt. Grundlæggende forsvarsteknik.', 'hal', NULL, '["forsvar"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('pad5f3qyh7', 'Stjæl bold eller afvis', 'Forsvaret øver to reaktioner mod dribling: 1) tackling ved at slå bolden ud nedefra, 2) afvisning ved at blokere med armene. Angriberen vælger tilfældig retning. Forsvar læser og reagerer. Træner beslutningstid for forsvaret.', 'hal', NULL, '["forsvar"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('xa2v7m0r6i', 'Færdiggørelse af tackling', 'Forsvar øver at færdiggøre en tackling: grib fat om skyderarm og led angriberen ud til siden. Angriber accepterer tacklingen og gennemfører kastet kontrolleret. Fokus på korrekt gribning og ledsagning – sikkert og regelret.', 'hal', NULL, '["forsvar"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('qievifizod', 'Tackling, så parade', 'Forsvar laver tackling på angriber i lille område – efterfulgt af en hurtig parade, når næste spiller skyder. Kombinationsøvelse der kræver hurtig omlæring fra aktiv tackling til blokering. Træner forsvarsovergange.', 'hal', NULL, '["forsvar"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('586vaj750e', 'Forsvar af stregspiller', '360 grader (3-4 angribere), 2-3 forsvarere, 1 stregspiller i midten. Angriberne forsøger at aflevere til stregspilleren, forsvarerne blokerer. Scorer et hold ved at nå stregspilleren, skifter de roller. Træner stregforsvar og blokering.', 'hal', NULL, '["opvarmning","småspil","forsvar"]', '[]', 4, NULL, NULL, 15, 'exercises/586vaj750e.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('sviwfa2q4v', 'Kvadratbold', '1 forsvar, 3 angribere. Angriberne må kun bevæge sig langs kanterne af et ca. 5x5 meter kvadrat. Forsvaret skal afbryde afleveringerne. Scorer angriberne et bestemt antal afleveringer, vinder de. Træner forsvarsbevægelse og afleveringsspil.', 'hal', NULL, '["opvarmning","småspil","forsvar"]', '[]', 4, 'fungerer godt. god til opvarmning', NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('jrjxlqk0v5', 'Stress med udkast', 'Spillere samlet i to diagonale fløje. Når foregående spiller har afsluttet/afleveret, sætter næste straks bolden i spil med et udkast. Hurtig rytme uden pauser. Simulerer kampens tempo og krav om hurtig opstart.', 'hal', NULL, '["kontra"]', '[]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('uz9evva7h2', '2 og 2 med retur', '2 og 2 løber kontra. Afslutteren går hjem efter skud. Den der ikke afsluttede løber retur som forsvar mod næste kontra fra den anden side. Træner hurtig omstilling fra angreb til forsvar og returløb.', 'hal', NULL, '["kontra","returløb"]', '[]', 0, 'fungerer rigtigt godt som beslutningsspil, fart og løb. Stor bane. 16-18 spillere er perfekt. Lav evt øvelse uden retur inden', NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('daeit8c0na', '3 mod 3 med retur', '3 og 3 løber kontra. Afslutteren går hjem, de to andre løber retur som forsvar mod næste kontra. Træner returløb, overtalsspil i kontra og hurtig omstilling.', 'hal', NULL, '["kontra","returløb"]', '[]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('qirqbmqmpv', '3 mod 3 med forsvar i én retning', '3 angribere løber kontra i én retning mod 2 forsvarere. 2 af angriberne bliver nye forsvarer  imod næste angrebshold. Øver overtal i angreb (3v2) og hurtig omstilling til forsvar.', 'hal', NULL, '["kontra"]', '[]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('u1fkhwnivt', 'Kontra med bande', 'Kontra 1 mod 1 med en fast ''bande''/tilspiller langs siden. Angriber bruger tilspilleren som væg og løber forbi. Forsvar skal aflæse hvornår der spilles til banden. Træner kontraspil og brug af tilspiller.', 'hal', NULL, '["kontra","returløb"]', '[]', 0, 'Også gerne med 2 mod 2. Så skal de starte længere tilbage

Har man to bander (en i hver side) er det også
En god øvelse ', NULL, 15, 'exercises/u1fkhwnivt.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('2fvuzl8x62', 'Duelkontra 2 og 2', 'To spillere om én bold spiller mod hinanden. Bolden placeres på midten. Begge løber ud og runder fx hver sin stol – den der får bolden, angriber. Den anden forsvarer. Intenst 1v1 i kontra. Træner reaktion og hurtig omstilling. Kombiner evt med en bande de kan spille', 'hal', NULL, '["kontra","returløb"]', '[]', 0, 'Variant: Lav en tilspiller der kan være bande', NULL, 20, 'exercises/2fvuzl8x62.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('sxoqvtjztr', 'Lange udkast', 'Kontra med lang aflevering i begge ender – en fast udkaster. Fokus på præcist langt udkast og angriberen der frigør sig til et dybt løb. Simulerer keeperens udkast i kampens kontraopbygning.', 'hal', NULL, '["kontra"]', '[]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('qmfq2rztj2', '2 og 2 op ad banen med 1+1 forsvar', '2 mod 2 på en bane delt på langs. Kan foregå i begge retninger simultant. Fokus på overtalsspil (2v2 med overtal ved hjælp af tilspiller) og forsvarets kommunikation. Træner kontrataktik.', 'hal', NULL, '["kontra"]', '[]', 0, NULL, NULL, 15, 'exercises/qmfq2rztj2.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('9nirj9sqfa', 'Shootout a la beach', 'Målvogter kaster ud til angriber der starter ved midterlinjen. Angriber løber kontra og skyder 1v0 eller 1v1. Hurtige gentagelser. Simulerer beach-handball-kontraen og træner keeperens udkastteknik.', 'hal', NULL, '["kontra"]', '[]', 0, NULL, 'https://www.youtube.com/watch?v=bWS-E1jvyqs', 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('bargb82pgw', '2 og 2 mod 1 forsvarer', '2 angribere mod 1 forsvarer. Forsvar starter på egen banehalvdel og forsøger at stoppe overtallet.  Efter afslutning bliver forsvar ny angriber, og 1 ny angriber sætter gang i bolden via keeper.
I mellemtiden har en ny forsvarer stillet sig frem i den anden ende
Træner 2v1-beslutning og forsvarets timing.', 'hal', NULL, '["kontra"]', '[]', 0, NULL, 'https://www.facebook.com/share/r/1ADB5TU578/?mibextid=wwXIfr', 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('0ruqu1ompu', '3 mod 3 med recovering defender', '3 angribere starter ved midterlinjen. 2 forsvarere på buen. Angriberne løber kontra mod de 2. Den 3. forsvarer løber efterfra og forsøger at indhente. Træner 3v2-overtal og forsvaret ved kontra.', 'hal', NULL, '["kontra","returløb"]', '[]', 0, NULL, 'https://www.facebook.com/share/v/187XM8Qfft/?mibextid=wwXIfr', 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('jg52lj6ofv', 'Skud efter stempelbevælgelse', '3 skridt frem mod forsvar, aflevering til tilspiller ved siden af, 3 skridt tilbage, modtag og skyd. Fokus på stempelbevægelsen: aktiv fremad-bagud-bevægelse for at skabe frirum til skuddet.', 'hal', NULL, '["skud"]', '[]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('1508tu6dic', 'Skud fra undergang', 'Back laver undergang: dribler ind under en forsvarer og kommer op til ny back-position. Skyd derfra. Giver naturlig udskiftning i øvelsen når man skifter plads med tilspilleren. Træner underkørslen som angrebsvåben.', 'hal', NULL, '["skud"]', '[]', 0, 'Variant: Skud fra ny midt. Begge varianter kan laves med paradespillere', NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('8rtbq5gwzt', 'Fløj/back skudøvelse - udad', 'Fløj og back på begge sider med en bold hver. Back spiller tilspiller på midt, som holder på bold. Fløj spiller back, som laver et let pres udad til en fløj der laver indspring fra høj position. Back laver tilbageløb til keglemarkering og får så bold fra tilspiller i høj fart på kant. Fokus på løbebane og afslutninger', 'hal', NULL, '["skud"]', '[]', 0, NULL, 'https://godhaandbold.dk/?page_id=54', 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('uq9cln4i0n', 'Fløj/back skudøvelse - indad', 'Fløj og back på begge sider med en bold hver. Back spiller tilspiller på midt, som holder på bold. Fløj spiller back, som laver et let pres udad til en fløj der laver indspring fra dyb position. Back laver tilbageløb til keglemarkering og får så bold fra tilspiller i høj fart til afslutning mellem 2 og 3. Fokus på løbebane og afslutninger', 'hal', NULL, '["skud"]', '[]', 0, NULL, 'https://godhaandbold.dk/?page_id=54', 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('9cie97nia0', 'Skud fra midt efter pres fra back', 'Skud fra midt efter pres fra back(rigtigt pres, ikke passivt) Træner er tilspiller på fløj. Øv at time afslutning med fart og pres.', 'hal', NULL, '["skud"]', '[]', 0, 'Kan også laves back, midt, back', NULL, 10, 'exercises/9cie97nia0.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('03vbs7ownu', 'Krydsøvelser', 'Skud efter AK (centerkryds) i to rækker, der krydser hinanden. Efter skud krydser man over til den anden kø. Fokus på korrekt AK-teknik og fart ved krydset. God flow-øvelse med mange skud. Sæt gerne sigtekegler op til den krydsende spiller, så de ikke løber for sidelæns', 'hal', NULL, '["skud"]', '[]', 3, 'God til at lære at man skal begynde at løbe før man har bolden. Svær for nybegyndere. Variant: Spillerne krydser ikke, men løber på yderside af sigtekeglerne.', 'https://www.instagram.com/reel/DQrTj5tCJOp/?igsh=MTgzYmFuMDFlaW5oYQ==', 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('075ls77ci2', 'Skud fra backs efter tilspil', 'Begge backs skyder skiftevis efter tilspil fra midt. Fokus på korrekt afleveringsmodtagelse og hurtig afslutning. Midt sætter bolden præcist, back afslutter i fart.', 'hal', NULL, '["skud","aflevering"]', '[]', 0, 'Variant: Backs laver forløb', 'https://danskhaandbold.dk/ovelsesbank/ovelse?id=136', 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('68ujs23roh', 'Skudbane', 'Stationsbane med kombinerede skudøvelser. Spillerne bevæger sig rundt – ingen stillestående kø. Sæt 3-5 stationer op med f.eks. hopskud, stempelfinte, nedhop, fløjskud. Effektiv skudtræning med mange gentagelser.', 'hal', NULL, '["skud"]', '["U9","U11"]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('xkzphowpgk', 'Skud fra position uden tilspil.', '15 skud per spiller fra 2-3 valgte positioner. Spilleren sætter selv bolden i gang og afslutter. Fokus på teknik og rolig gentagelse. Velegnet til at øve afsætspunkt og skudretning.', 'hal', NULL, '["skud"]', '["U9","U11"]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('possp2ofgw', 'Fløjskud: Skud fra hjørnet', 'Hop uden tilløb fra en kegle lagt på baglinjen. Skyd efter vejledning fra træner om mål-hjørne. Fokus på eksplosivt afsæt på ét ben og boldkontrol i luften. Grundlæggende fløjskudsteknik.', 'hal', NULL, '["skud"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ancywvjbt8', 'Fløjskud efter indspring', 'Indspring fra 3 skridt op over evt. hæk. Fokus på kraftfuldt indspring, korrekt afsæt og tilt af kroppen mod målet. Gerne over forhindring for at tvinge korrekt bevægelse.', 'hal', NULL, '["skud"]', '[]', 0, 'Lav gerne en fløjskudsbane med tre minimål; indspring højre, venstre og stående', NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('8tv33455aq', 'Fløjskud med glidefald', 'Kombiner fløjskud med glidefald: skyd og glid hen ad gulvet ved landing. Øv glidefaldsteknikken separat først. Pas på at glidefald ikke tager fokus fra skuddets kvalitet.', 'hal', NULL, '["skud"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('m8x2lian02', 'Assisten', 'Kombineret øvelse: Back modtager tilspil fra midt, og afslutter i fart. Tilspiller tager minimum 10 tilspil, og øver sig i at ramme en afslutter i fart. Kan med fordel kombineres med målmandstræning', 'hal', NULL, '["skud","aflevering"]', '[]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('olwne836bf', 'Back-midt-back retur', 'Back presser til midt, midt presser til modsatte back, og presses kørers retur til back, der afslutter direkte. Herefter sætter modsatte back gang i en bold Fokus på tilbageløb og timing af returafleveringen. Sæt evt. fløje på som afslutter i en yderligere iteration', 'hal', NULL, '["aflevering","skud"]', '[]', 0, 'God øvelse. Fungerer godt med VB, M, HB - dog giver det ikke stress nok uden forsvar. Kan med fordel efterfølges af 3 mod 3 på et mål', NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('srjqgte0qo', 'fløj-back-midt pres retur', 'Fløj og back presser til midt, der presser retur. Afslutning fra fløj. Fokus på tempo, timing og korrekt presreturbevægelse. Spillerne skal holde høj fart og aflevere præcist.', 'hal', NULL, '["aflevering","skud"]', '[]', 0, 'God til timing og grundspil uden det bliver for kedeligt. Når den sidder så fokuser på selve presset', NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('j965o801vd', 'Basalt 3pres', '3 mod 3 med trænere i fløj. Backs starter pres. Øv grundlæggende angrebs-presform: back presser, midt frigør sig, back retur. Trænere i fløjen giver tilspil og varierer spillet. Lær den basale presstruktur.', 'hal', NULL, '["aflevering","skud"]', '[]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('cm35mwu4wg', '3 mod 3 på halvbane', '3 mod 3 på halvbane. Forsvar placeret mellem kegler. Angrebsholdet laver pres fra backs, eller fra midt. Kombiner gerne med aftaler og forløb. Fokus på angrebspres og forsvarets bevægelse og kommunikation.', 'hal', NULL, '["sammenspil","beslutning","duel"]', '[]', 5, 'Virker godt. Ikke for nybegyndere', NULL, 20, 'exercises/cm35mwu4wg.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ca5w0mqnf0', '4 mod 4 i midtzone på halvbane', '4 mod 4 på halvbane. Fokus på forsvaret i midtzonen: tæt på angriberne, god kommunikation. Angrebsholdet øver presopbygning med 4. Svarende til 3v3 men med stregspiller og en ekstra forsvar.', 'hal', NULL, '["sammenspil","forsvar","taktik"]', '[]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('piii2czhuv', 'Fuldt grundpres', '5 på buen (3 bagspillere, resten fløje med en bold hver). Øv det fulde grundpres: backs laver pressekvens, fløje involveres. Fokus på timing og rækkefølge i presset.', 'hal', NULL, '["sammenspil","aflevering"]', '[]', 0, 'Variant: Spil med 1 forsvar i hver side, eller 2 forsvarer der skifter side, så det essentielt bliver "gode beslutninger" på back/fløj', NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('dci5m6lnbv', '5 mod 5 på halvbane', '5 mod 5 på halvbane. Fokus på placering og pres: Hvordan skabes overtal? 3 backs + 2 fløje. Forsvar øver opbakning og højde. Realistisk halvbane-situation.', 'hal', NULL, '["sammenspil","beslutning","taktik"]', '["U11","U13","U15","U17"]', 0, 'på den vis kan der øves afslutninger på stort mål i den anden ende', NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('mdq6xuq8ss', '6 mod 6 på halvbane', '6 mod 6 på halvbane. Fokus på stregspillet og overtalskabelse: Hvordan skabes gennembrud ved stregen? Alle positioner besatte. Realistisk kamp-lignende situation med taktisk fokus.', 'hal', NULL, '["sammenspil","beslutning","taktik"]', '["U11","U13","U15","U17"]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('rbsgcwy31v', '2 mod 2 på halvbane', '2 mod 2 på halvbane. Fokus på individuel duel og forsvarsbevægelse. God isoleret 1v1-situation for forsvar og angreb. Skiftes i roller efter afslutning.', 'hal', NULL, '["sammenspil","forsvar","duel"]', '[]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('9pxjufr12x', '2 mod 2 på halvbane med streg', '2 mod 2 (inkl. stregspiller). Med tilspiller. God til at træne screening (stregspillerens blokering) og angrebets brug af stregen til at skabe frirum.', 'hal', NULL, '["sammenspil","beslutning","forsvar"]', '[]', 0, 'Enten i midtzone eller på back', NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('elchmsv18y', 'Gode beslutninger - udspil', '1 forsvar mod back + fløj. Back får tilspil fra midt og må vælge: skyd eller aflever til fløj. Forsvar reagerer. Træner angrebets beslutningstagen i simpel 2v1-situation.', 'hal', NULL, '["sammenspil","beslutning","taktik"]', '[]', 0, NULL, NULL, 20, 'exercises/elchmsv18y.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('j1xhr28djw', 'Gode beslutninger - 3 midtblok', '2 forsvarere mod back, midt, back. Angriberne øver pressekvensen og beslutninger. Forsvar øver at blokere midterrum. Ingen returnering – fokus på angrebets valg.', 'hal', NULL, '["sammenspil","beslutning","taktik"]', '[]', 0, NULL, NULL, 20, 'exercises/j1xhr28djw.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('mbg3wwbmxl', 'Gode beslutninger - 4 midtblok', '3 forsvarere mod back, midt, back og streg. Ingen returnering. Angriberne øver at inkludere stregspilleren i beslutningerne. Forsvar øver 3-mod-4 taktik og boldorientering', 'hal', NULL, '["sammenspil","beslutning","taktik"]', '[]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('tjl0mz1x6k', 'Gode beslutninger - overgang', '1 forsvarer, 1 midt/back, 1 stregspiller/overgangsspiller. Lad midt/back få tilspil og træffe beslutning: play til streg eller skyd selv. Forsvar skal dække begge muligheder. Realistisk 2v1-overgang.', 'hal', NULL, '["sammenspil","beslutning","taktik"]', '[]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('vlqb3mqz0n', 'Offensivt forsvar (4 mod 4)', '4 mod 4 inkl. streg. Forsvareren møder boldholder offensivt – tæt markering og pres. Angrib bolden aktivt. Træner agressivt forsvarsspil og offensiv individuel markering.', 'hal', NULL, '["sammenspil","duel","taktik"]', '["U11","U13","U15","U17"]', 5, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('e2bcvwoz7w', '3 mod 3+1 stationær streg.', 'Angreb øver beslutninger med en fast stationær stregspiller. Forsvar skal være god til at bevæge sig og kommunikere om stregen. 3+1 mod 3. Fokus på angrebets brug af stregspilleren og forsvarets kommunikation og boldorientering. God forberedelse til 3-2-1 forsvar.', 'hal', NULL, '["sammenspil","beslutning","forsvar"]', '[]', 5, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('1zie4yr5vm', 'Futtog: Fløjovergang med bold', '4 mod 4. Fløj, midt, 2x backs. Fløj løber overgang med bold (futtog-bevægelse). Forsvaret tilpasser sig. Øver den koordinerede fløjovergang som taktisk virkemiddel.', 'hal', NULL, '["sammenspil","taktik","forsvar"]', '["U9","U11"]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('09bfg44l0m', 'Futtog: Fløjovergang med bold med streg', '5 mod 5 inkl. streg. Fløj løber overgang med bold mens stregspilleren screener på inderside af fløj. Mere kompleks version af futtog-bevægelsen med stregen som ekstra element.', 'hal', NULL, '["sammenspil","taktik","forsvar"]', '["U11","U13","U15","U17"]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('41tnv12fox', 'Blind overgang', '4 mod 4. Fløj løber overgang uden bold (blind side). Modsatte back starter pres, og overgangen timer indløbet med dette. Forsvar skal kommunikere om den blinde overgang.', 'hal', NULL, '["sammenspil","taktik","forsvar"]', '[]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('b9pr4xy87o', 'Blind overgang med streg', '5 mod . Fløj, midt, 2x backs, sterg. Sidste fløj er blind. Streg står på inderside af 2er i den side overgangen kommer fra. Fløj løber overgang uden bold forbi  modsatte 3er. Modsatte back starter pres, og overgangen skal time med det. Den pressende back skal træffe det gode valg', 'hal', NULL, '["sammenspil","taktik","forsvar"]', '["U11","U13","U15","U17"]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('m7yvsddvtq', '5 mod 4 på halvbane', '5 angribere mod 4 forsvarere. Øv overtal i angreb og lær forsvarerne at bevæge sig til at dække undertallet. Forsvar kommunikerer om hvem der dækker det ekstra angrebsled.', 'hal', NULL, '["sammenspil","beslutning","taktik"]', '["U9","U11"]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('260qzjlvlc', '4 mod 4 med AK', '4 mod 4 uden fløje. Øv AK (centerkryds) og returpres med screening. Fokus på fart og timing i AK-bevægelsen.', 'hal', NULL, '["sammenspil","beslutning","taktik"]', '["U11","U13","U15","U17"]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('f21q4dt7ju', 'Rullepres', 'Øv fløjoprulning som returpres: Fløjen ruller ind i banen og overtager en backs presseopgave. Backs skifter positioner i pres. Koordineret presform der kræver god timing og kommunikation.', 'hal', NULL, '["sammenspil","beslutning","taktik"]', '[]', 0, 'Skal laves med forsvar ellers giver det ikke noget', 'https://issuu.com/dhf_publikationer/docs/tr_ningsprogram_u11_uge_2_1_36489f85d63306?fr=sNTQ5OTgzNzE4MDc&utm_source=agillic&utm_medium=email&utm_campaign=Trænningsprogrammer+U11+Uge+52', 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('za5icqx1yh', 'Skud i bunden af målet', 'En serie skud til keeperens ene fod. Keeper øver at redde lavt med foden. Skal over til modsatte stolpe mellem skud. Fokus på korrekt fodbevægelse og lavt tyngdepunkt. Grundlæggende keepertræning.', 'hal', NULL, '["keeper"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('a3saa4zrka', 'Skud i toppen af målet', 'En serie skud til keeperens ene hånd i toppen. kal over til modsatte stolpe mellem skud Skift side løbende. Fokus på korrekt håndstilling og spring til bolden.', 'hal', NULL, '["keeper"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('m35hvx63g1', 'Skud i siden af målet', 'En serie skud til forudbestemt side – kan variere mellem høj og lav. Keeper kender siden og fokuserer på korrekt teknik. Øver målrettet reaktion og korrekt positionering.', 'hal', NULL, '["keeper"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('pvssukrmk4', 'Fløjskud', 'Keeperens positionering og teknik ved fløjskud. Fokus på at komme ud i god vinkel n. Keeper øver afstand til fløj og timing af udspring.', 'hal', NULL, '["keeper"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('i4ulskrp2n', 'Hurtige bevægelser', 'To skud i træk i hver sin side. Keeper skal reagere hurtigt på andet skud efter første redning/forsøg. Fokus på at få arm og ben med i begge retninger. Kræver eksplosiv lateral bevægelighed.', 'hal', NULL, '["keeper"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('qf8amp50tq', 'Nærskud', 'Øv nærskud: skud over keeperens hoved og i hoften fra tæt hold. Fra fløj eller back, indefra eller udefra. Fokus på hurtig reaktion ved kort afstand og korrekt positionering: Angrib skytten', 'hal', NULL, '["keeper"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('hv1t7qgd9d', 'Sidebevægelser', 'En serie skud fra hele buen fra en side til den anden fra markspillere linet up langs buen. Keeper bevæger sig sidelæns med bolden og reagerer på skud. Øver lateral bevægelighed og timing.', 'hal', NULL, '["keeper"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('cd1lkkmvrv', 'Kamp med regler', 'Kamp med standard regler, som opgiverkast, straffe osv', 'hal', NULL, '["kamp"]', '[]', 5, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('kuk107vrcu', 'Kaoskamp', 'Kamp med shotclock: Holdet har 15 sekunder til at afslutte hvis modstanderen ikke scorer. Pres på hurtig beslutning og afslutning. Masser af skud og kontraer. Højt tempo.', 'hal', NULL, '["kamp"]', '[]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('rhksro9ovs', 'Kamp med bonusbold', 'Kamp der belønner hurtig omstilling: scoring efter kontra eller 2. bølge giver en ekstra bold (bonusbold). Incitament til at sætte hurtigt i gang efter mål. Træner offensiv omstilling og kontrabevidsthed.', 'hal', NULL, '["kamp"]', '[]', 5, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('8mvj4ctmfa', '3 kamp', 'Tre hold i rotation. To hold spiller, det tredje hviler. Tabende hold går ud, vindende spiller mod det hviler. Alle hold kæmper for at forblive på banen. Intenst og konkurrencepræget.', 'hal', NULL, '["kamp"]', '[]', 0, NULL, NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ccp5elfhcz', 'Minikamp', 'Kamp på minibane med fokus på helbanepres og uden dribling. Ingen dribling tvinger hurtige afleveringer og godt positionsspil. Lille bane øger intensiteten og antallet af boldberøringer.', 'hal', NULL, '["kamp"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('1uy8et4926', 'Faldteknik: Glidefald fra siddende', 'Sæt jer på knæ, sæt af fremover og skub jer fremad med hænderne langs siden af kroppen. Land blødt på brystet og mave. Første skridt i at lære korrekt glidefaldsteknik – starter fra lav højde.', 'hal', NULL, '["faldteknik"]', '[]', 0, NULL, 'https://www.youtube.com/watch?v=hRkQN3IHjWs&list=PLNssDT7zACUVFlcVKx81QAsahz_MtLLTS', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('amkripafhl', 'Faldteknik: Glidefald efter kast fra siddende', 'Sid på knæ med bold. Sæt af fremover, kast bolden i luften og land i glidning på mave/bryst. Kombinerer kast og fald. Øver timingen mellem udspring og boldafgivelse.', 'hal', NULL, '["faldteknik"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('n5gxvdelrb', 'Faldteknik: Glidefald fra stående med let tilløb', 'Stå oprejst, tag et par hurtige skridt, afsæt og land i glidning på brystet. Skub frem med hænderne ved siden af kroppen. Øver glidefald fra normal stående position med tilløb.', 'hal', NULL, '["faldteknik"]', '[]', 0, NULL, 'https://www.youtube.com/watch?v=31H56oMMABU&list=PLNssDT7zACUVFlcVKx81QAsahz_MtLLTS&index=2', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('6i116z5gaa', 'Faldteknik: Glidefald  efter  afslutning i fart', 'Hop indover med  en bold, kast bolden, land på brystet og skub jer fremad på gulvet med hænderne', 'hal', NULL, '["faldteknik"]', '[]', 0, NULL, 'https://www.youtube.com/watch?v=fjQXd6bwp5Y&list=PLNssDT7zACUVFlcVKx81QAsahz_MtLLTS&index=3', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('8upr7m1s7y', 'Faldteknik: Glidefald  efter  afsætning fra bænk', 'Hop med tilløb op på bænk med  en bold, kast bolden, land på brystet og skub jer fremad på gulvet med hænderne', 'hal', NULL, '["faldteknik"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ljcuhhruur', 'Faldteknik: Stikbold med glidefald', 'Stikbold-spil. Rammes man af bolden, stiller man sig i bro (på alle fire med maven opad). Befries ved at en holdkammerat laver et glidefald under broen. Sjov kombination af leg og glidefaldstræning.', 'hal', NULL, '["faldteknik","opvarmning"]', '[]', 0, NULL, 'https://www.youtube.com/watch?v=XVOW56N2xhA&list=PLNssDT7zACUVFlcVKx81QAsahz_MtLLTS&index=4', 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('wchr031rwkqmmlq2f7j', 'Pump armen', 'Lav 2-3 skudfinter med høj arm inden der kastes til makker', 'hal', NULL, '["aflevering"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('g0vq9dtd1zsmmlq48b4', 'Skud fra to rækker', 'To rækker, der skyder i kort side hos keeper. Hver runde er enden oppe, nede, eller valgfri - men altid i kort side. Keeper øver bevægelser i målet', 'hal', NULL, '["keeper"]', '[]', 5, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('pnlgnjc4jzmmlq6kvi', 'Skud fra backs efter tilspil med forløb', 'Spillere på backs i begge sider. Får tilspil fra midt. Inden bolden modtages laves forløb på stol, madras eller lignende, hvorefter der afsluttes. Øv til begge sider', 'hal', NULL, '["aflevering","teknik","skud"]', '[]', 0, NULL, NULL, 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('m8my02xg1ehmmlqa02m', '3 mod 3 I bølger', '3 forsvarer i midtzonen. 3 angribere kommer i 2 bølge i fart og forsøger at komme på kant eller afslutte fra distance. Forsvarer skal lukke ned, afvise eller erobre bolden. Derefter kommer 3 nye angriber. Lav 10 bølger til et forsvarshold', 'hal', NULL, '["kontra","forsvar","sammenspil"]', '[]', 0, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('41ja1clrt3gmmlqc40z', '4 mod 3+1 i bølger', '4 forsvarer, i 3-2-1 pyramide i midtzonen. Fast stregspiller. 3 angrebsbagspillere kommer i 2 bølge, og forsøger at score i samarbejde med streg. Forsvar skal afvise og lukke ned. Herfter kommer en ny bølge af 3 angribere. Lav 8-10 angreb til hvert forsvarshold og byt så', 'hal', NULL, '["forsvar","kontra","sammenspil"]', '[]', 5, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('m19yeuhpg7dmmlxo17r', '2 mod 2 kontraøvelse fra firkant. Diagonalerne er sammen', 'Fire spillere stiller sig op i en firkant ved egen tremeter, hvor de to på samme diagonal arbejder sammen som ét hold mod de to på den anden diagonal. Ene hold er angreb, det andet forsvar. Den ene spiller på angreb starter med bolden, og kan enten spille medspiller eller starte med at drible. Så snart bolden er sluppet er spillet igang. Næste gang byttes der, så forsvar er angreb og vice versa.', 'hal', NULL, '["kontra"]', '[]', 5, NULL, NULL, 15, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('7sfq1s8icgnmmomlis7', 'Træk hinanden i en arm', 'Spillerne står parvis overfor hinanden og holder hinanden i højre hånd. På trænerens signal skal spillerne prøve at trække den anden ud af balance. Øvelsen træner eksplosiv kraft i benene, balance og forbedrer spillernes forståelse for kropskontrol under dynamiske bevægelser.', 'hal', NULL, '["styrke","opvarmning"]', '[]', 0, 'Varier om der stås på et eller to ben. Varier hånd', 'https://www.instagram.com/reel/DTv9yxgEUhu/?igsh=NHNlMXQ1a3hramJh', 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('a1ewqvkgp7hmmomn6bh', 'Skubbekamp med siden til', 'To spillere står vendt mod hinanden med siden til. De placerer deres hånd mod hinandens skulder eller hofter og skubber hinanden uden at løfte fødderne fra jorden. På kommando skifter de hvilken side, der skal være mod hinanden. Øvelsen træner balanceevne, kropskontrol og styrke i benene.', 'hal', NULL, '["opvarmning","styrke"]', '[]', 0, NULL, 'https://www.instagram.com/reel/DTv9yxgEUhu/?igsh=NHNlMXQ1a3hramJh', 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('qrfnvtj3v4mmomo6cy', 'Skubbekamp med siden til på alle 4', 'To spillere stiller sig overfor hinanden på alle 4, med siden til mod hinanden. På trænersignal skubber de mod hinanden med hoften og skuldrene for at tvinge modstanderen væk fra sin position. Øvelsen træner kernestabilitet, balance og fysisk styrke.', 'hal', NULL, '["opvarmning","styrke"]', '[]', 0, NULL, 'https://www.instagram.com/reel/DTv9yxgEUhu/?igsh=NHNlMXQ1a3hramJh', 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('pm44w0vpzkmms7z39p', '4 mod 4 (1 fløj, uden streg): Pres og returpres med forsvar', 'Fire angribere spiller mod fire forsvarere på en halv bane uden streg og fløj i en side. Lad back i fløjens side starte pres, og kør det retur.  Begge backs skal angribe på kant, og den ene har selvfølgelig mulighed for udspil. Forsvar skal være aggressivt, og forsøge spilstop. Skift forsvar og side efter behov', 'hal', NULL, '["sammenspil"]', '[]', 5, 'sæt AK på. Svær for nybegyndere', NULL, 20, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('mku7mao03asmmt68ybi', '2 og 2 op ad banen med 1 forfølger', 'To angribere starter med bolden og løber op ad banen,. En forsvarer starter som "forfølger" bagved angriberne og skal prøve at blokere eller få bolden. Angriberne skal samarbejde med pasninger og fart. Øvelsen træner hurtige modangreb, pasningsspil under pres – og det hele tempo.', 'hal', NULL, '["aflevering","kontra","returløb"]', '[]', 5, 'Kan gerne køre i to retninger', NULL, 10, 'exercises/mku7mao03asmmt68ybi.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('f58oauyrk6immuii50t', '3 mod 3 med indløb', 'Tre angribere, tre forsvarer imellem to kegler i midtzonen. En af angriberne laver overgang. Forsvarer skal samarbejde og stadig være aggresive', 'hal', NULL, '["taktik","forsvar","overgang"]', '[]', 0, NULL, NULL, 15, 'exercises/f58oauyrk6immuii50t.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('6gtxfpmv9fymn0vrk84', 'Offensivt forsvar (4 mod 4)', '4 mod 4 inkl. streg. Forsvareren møder boldholder offensivt – tæt markering og pres. Angrib bolden aktivt. Træner agressivt forsvarsspil og offensiv individuel markering.', 'hal', NULL, '["sammenspil","duel","taktik"]', '[]', 5, NULL, NULL, NULL, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('o8dqcrmiqebmn0vrk84', '6 mod 5 på halvbane', '6 angribere mod 5 forsvarere. Øv overtal i angreb og lær forsvarerne at bevæge sig til at dække undertallet. Forsvar kommunikerer om hvem der dækker det ekstra angrebsled.', 'hal', NULL, '["sammenspil","beslutning","taktik"]', '[]', 0, NULL, NULL, NULL, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('gw67fr10yyomn0w74sf', 'Armbøjninger', 'Armstrækkere (push-ups): Ligge på maven med hænderne skulderbredde fra hinanden. Sæt ned til brystet nær gulvet og stræk armene. Fokus på lige krop. Træner bryst, skuldre og triceps.', 'hal', NULL, '["styrke"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('62cw73o61zemn0w74sf', 'Rygbøjninger', 'Lig på maven med hænderne bag nakken eller langs kroppen. Løft overkroppen fra gulvet ved at spænde rygmusklerne. Hold kort og sænk kontrolleret. Træner de nedre ryg- og rygmuskler.', 'hal', NULL, '["styrke"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('yomyud1vtsgmn0w74sf', 'Reaktionsøvelse', 'Par eller grupper: Reagér på signal (lyd, syn eller berøring) med en bestemt bevægelse. F.eks. grib en bold, rejs dig fra siddende eller sprint til markering. Kan varieres frit. Træner reaktionstid.', 'hal', NULL, '["styrke"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ng79zjpdpfsmn0w74sf', 'Mavebøjninger', 'Ligge på ryggen med bøjede knæ. Løft overkroppen mod knæene, hold kort og sænk kontrolleret. Fokus på at spænde mavemusklerne aktivt. Basis core-styrkeøvelse.', 'hal', NULL, '["styrke"]', '[]', 5, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('2ys65iyxzntmn0w74sf', 'Lunges', 'Stå oprejst. Tag et stort skridt frem og sænk bageste knæ mod gulvet. Rejs dig og saml. Skift ben. Fokus på oprejst ryg og at det fremre knæ ikke går forbi tåspidserne. Træner quadriceps, baglår og hofte.', 'hal', NULL, '["styrke"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('k3mydcc18crmn0w74sf', 'Planken', 'Lig i pushup-position på underarme og tæer. Hold kroppen rank som en planke – ingen sænkning af hoften. Hold i 20-60 sekunder. Evt. med en makker der hopper let over spilleren fra side til side. Træner core og stabilitet.', 'hal', NULL, '["styrke"]', '[]', 0, NULL, NULL, 4, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('sxwqx2fdelbmn0w74sf', 'Avancerede mavebøjninger', '2 og 2: Spiller 1 ligger med hovedet mellem spiller 2''s fødder (ryg mod gulv). Spiller 2 holder spiller 1 i fødderne og spiller 1 laver mavebøjninger op og lægger sig kontrolleret tilbage. Intensiverer maveøvelsen.', 'hal', NULL, '["styrke"]', '[]', 0, NULL, 'https://www.instagram.com/reel/DJ9PkajNFJU/?igsh=ZWNmZG9zd2doejE0', 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('69bvm0zaa16mn0x7ssa', 'Aben i træet', 'Spillerne står i par, hvor den ene er "aben" og den anden er "træet".  Aben skal klatre hele vejen rundt om træet uden at røre jorden. Træet må gerne hjælpe til. Tag evt tid.', 'hal', NULL, '["styrke","opvarmning"]', '[]', 3, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('exd3n1d6ejhmn2sd9kq', '3 mod 3 på fløj,  back, midt.', 'Lad fløj eller midt starte pres.', 'hal', NULL, '["sammenspil","duel","taktik"]', '[]', 0, NULL, NULL, NULL, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('95b8i9isvnemn4un4v6', '3 mod 3 med retur i begge retninger', 'Del fuldbane på langs med kegler. Kegler skal være ca 3m fra 3m linjen.
3 løber kontra på ene halvdel, efter afslutning starter 3 i den anden retning. De tidligere angriber skal runde sidste kegle og løbe retur
', 'hal', NULL, '["kontra"]', '[]', 0, 'Kan også køres 2 mod 2', NULL, 20, 'exercises/95b8i9isvnemn4un4v6.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('cscraeyioihmn5wnfnk', '3 på stribe med kroppen som brikker', '9 kegler i matrix i den ene ende af hallen.
2 x hold af 3 i den anden ende. 3 i en farve vest.
Første hold til at stå tre på stribe vinder.
Lav gerne to baner', 'hal', NULL, '["opvarmning","stafet","leg"]', '[]', 5, NULL, 'https://www.instagram.com/reel/DWLf6D2jZEZ/?igsh=MWEzaTI5bGNsZjU1dw==', 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('cup63ikgfzgmn5yhn8d', 'Tacklingsøvelse i trekant', 'Hold af 3:  1 forsvarer 2 angribere.
De to angribere skiftes til at angribe ind mod forsvarer. Fokus på korrekt tackling.
Lad angribere presse forsvar. Husk at bytte
Tilføj hop for øvede.', 'hal', NULL, '["forsvar"]', '[]', 0, NULL, NULL, 6, 'exercises/cup63ikgfzgmn5yhn8d.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('3qev3aq518nmn7z3r48', '3 mod 3 med offensivt forsvar', 'I denne øvelse spiller tre angribere mod tre forsvarere på en halv bane. Angriberne forsøger at score ved at passe og løbe sig fri, mens forsvarerne presser dem højt op på banen og prøver at stjæle bolden før skuddet. Øvelsen træner både hurtig passpil og bevægelse uden bold for angriberne, samt aggressiv forsvarspil og kommunikation for forsvarerne – og det hele på et lille område hvor der ikke er plads til at være passiv.', 'hal', NULL, '["aflevering","forsvar","taktik"]', '[]', 0, NULL, NULL, NULL, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('5xyur0r6e27mng0m1lh', 'Fløj og back skud: udspil og skud over parade', 'En forsvarer, resten i kø på fløj og back med bold.
Back modtager bold fra fløj, finter indad og skyder over paradespiller.
Næste i backrækken laver udspil til fløj som skyder efter indspring , mens paradespiller presser 
', 'hal', NULL, '[]', '[]', 0, NULL, NULL, 15, 'exercises/5xyur0r6e27mng0m1lh.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('jfe1pq8yhnkmng1fdef', 'Back og center: skud efter forløb og runding', 'Alle på back eller center med bold. Tilspiller ud fra back.

Back spiller TS laver forløb og får bolden indover og afslutter.
Derefter spiller center til TS, runder TS og afslutter udad', 'hal', NULL, '["skud"]', '[]', 0, NULL, NULL, 15, 'exercises/jfe1pq8yhnkmng1fdef.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('b5lnkvi646tmng27li4', 'Back og overgang: skud indover midt og efter indløb', 'Spiller fordelt på VB og HF (eller omvendt) med bold hver. TS på straffepletten.
Fløj afleverer til TS, løber overgang for TS og får bold i runding og afslutter.
Derefter spiller VB TS og får bold tilbage og afslutter over TS.', 'hal', NULL, '["skud"]', '[]', 0, NULL, NULL, 15, 'exercises/b5lnkvi646tmng27li4.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('tekrxizhz6nmng4pa8i', 'Afslutning under pres', 'Parvist. 4 kegler er stillet op ved tremeter.
Parrene stiller op ved midterlinje, forsvarer 1-2 meter bagved angriber.
Forsvar starter med bold, og afleverer til angriber, der nu skal nå ned og afslutte på YDERSIDEN af deres tildelte kegle. Forsvar skal forsøge at forhindre scoring.', 'hal', NULL, '["kontra","skud"]', '[]', 0, 'Varier afstand mellem forsvar og angreb efter niveau.', NULL, 15, 'exercises/tekrxizhz6nmng4pa8i.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('wtjcwjpvz0imng50g63', 'Aflevering og Skud efter pladsskifte', 'Alle spillere på VB eller Center. Tilspiller med bolde i VF. 
Pres fra VB til Center, som afleverer retur til VB, løber over på HB og får en lang aflevering og slutter på ydersiden .

God øvelse til at øge afleveringsniveau.', 'hal', NULL, '["aflevering","skud"]', '[]', 0, 'Begge sider', NULL, 15, 'exercises/wtjcwjpvz0imng50g63.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('65ekltnwfglmng52i93', 'Afslutning efter back-back aflevering.', NULL, 'hal', NULL, '["aflevering","skud"]', '[]', 0, NULL, NULL, NULL, 'exercises/65ekltnwfglmng52i93.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('0vmmql7d43pmng5afrp', 'Fløj/back afslutning med forsvar', 'Alle spillere på fløj eller back med bolde. Kan godt køres i to sider skiftevis.

Fløj og back bytter bold. Fløj laver indsætning og afslutter, og bliver derefter forsvar på back.
Angrebsback spiller bande med TS på center 1:1 mod forsvar.', 'hal', NULL, '["skud","duel"]', '[]', 0, NULL, NULL, 10, 'exercises/0vmmql7d43pmng5afrp.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('pri603l2unmng5er27', '3 mod 2 efter udkast', '2 forsvarsspillere.
2-3 midtspillere på egen banehalvdel.
Resten i to fløje.
Ene fløjside har bold, spiller in til keeper TS som laver langt udkast til modsatte banehalvdel til fløj.
Fløje runder kegle og har nu 3 mod 2 situation mod mål.

De to fløje bytter efter afslutning med forsvarerne', 'hal', NULL, '["aflevering","kontra","sammenspil"]', '[]', 0, NULL, NULL, 15, 'exercises/pri603l2unmng5er27.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('3dhtjpva1mbmng5gosv', '2 mod 2 med udkast', '2 forsvarsspillere. Resten i to fløje. Ene fløjside har bold, spiller in til keeper TS som laver langt udkast til modsatte banehalvdel til fløj. Fløje runder kegle og har nu 2 mod 2 situation mod mål. De to fløje bytter efter afslutning med forsvarerne', 'hal', NULL, '["aflevering","kontra","sammenspil"]', '[]', 0, NULL, NULL, 20, 'exercises/3dhtjpva1mbmng5gosv.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('3obpet2zvl2mng5j4rf', 'Kapløb med udkast', 'Alle i to fløje, med tilspiller på modsatte banehalvdel.
Ene fløj kaster til keeper, som kaster til TS.
Første fløj der runder TS er angriber, anden er forsvarer', 'hal', NULL, '["aflevering","kontra"]', '[]', 0, NULL, NULL, 15, 'exercises/3obpet2zvl2mng5j4rf.jpg', NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('wlac604m5u', 'Kontrollerede hop på samlet', 'Stå med samlede ben. Hop på stedet og fokusér på kontrolleret landing: bløde knæ, hoftebreddes afstand ved landing, tyngdepunktet lavt. 10 gentagelser. Grundlæggende plyometrisk opvarmning der aktiverer ankler og knæ.', 'fys', NULL, '["plyometrik"]', '[]', 4, 'Land på forfoden!', NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('3yuhnxbid9', 'Pogo hops', 'Hop på samlede ben med hurtig afsæt – som en pogo-stick. Minimal kontakttid med gulvet, fokus på hurtig og elastisk afsætning fra anklerne. 10 konsekutive hop. Træner ankelelasticitet og rytme.', 'fys', NULL, '["plyometrik"]', '[]', 5, 'Land på forfoden!', NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('uhu40pjncf', 'Hop fra knælende position', 'Sid på knæ. Rejs dig op til stående uden brug af arme – kun benenes kraft. Lav derefter et normalt hop. 10 gentagelser. Styrker quadriceps og øver eksplosivt knæekstension.', 'fys', NULL, '["plyometrik"]', '[]', 4, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('cmujkp8avz', 'Saksehop', 'Start i udfaldsposition (lungestilling). Hop op og skift ben i luften (saksebevægelse). Land i modsatte udfaldsposition. 20 non-konsekutive gentagelser. Træner eksplosiv kraft og koordination i benene.', 'fys', NULL, '["plyometrik"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('xbig7wk2r5', 'Boxjump', 'Stå foran en boks eller bænk. Hop op med samlede ben og land blødt på boksens overflade. Trin ned og gentag. 10 konsekutive gentagelser. Grundlæggende boxjump der træner eksplosiv hoppekraft.', 'fys', NULL, '["plyometrik"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('do9tdqkbf4', 'Boxjump bounce', 'Stå ovenpå boksen. Hop ned på gulvet og sæt straks af igen med et hop op på boksen. 10 konsekutive gentagelser. Minimal kontakttid med gulvet. Træner reaktivkraft og ankelelasticitet.', 'fys', NULL, '["plyometrik"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('v84gndxv5m', 'Hop i firkant med samlede ben', 'Fire kegler/markeringer i firkant. Hop fra felt til felt (frem, til siden, tilbage, til siden) på samlede ben. 20 konsekutive gentagelser. Træner lateral og fremadgående hoppekraft.', 'fys', NULL, '["plyometrik"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('5r66lrftu8', 'Hop i firkant på et ben', 'Samme som firkanthop men på ét ben. 10 hop pr. ben (2 sæt). Kræver god balance og enbensstyrke. Træner lateral stabilitet og enbensstyrke i ankel, knæ og hofte.', 'fys', NULL, '["plyometrik"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('yb1nvdybg6', 'Skaterhops til siden', 'Hop sidelæns fra ét ben til det andet – som en skøjteløber. Land på det yderste ben og hold positionen kort. Non-konsekutive, 20 gentagelser. Træner lateral eksplosivitet og balancekontrol.', 'fys', NULL, '["plyometrik"]', '[]', 0, NULL, 'https://www.instagram.com/p/DK_aq74Mdmn/', 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('40d39sf2cf', 'Hop i firkant med sidestep (mors-thy)', 'Spillerne står i en firkant (tegnet med kegler eller bånd) og hopper rundt langs siderne med små, hurtige sidestep. De hopper på begge ben samtidig og bevæger sig sidelæns rundt om firkanten uden at træde uden for linjerne. Øvelsen træner ben-styrke, koordination, balance og hurtige fodarbejde, som er vigtig for at kunne bevæge sig hurtigt på banen. Det er en sjov og konkurrencepræget opvarmning, der gør børnene klar til træningen.', 'fys', NULL, '["plyometrik"]', '[]', 4, NULL, 'https://www.instagram.com/p/DK_aq74Mdmn/', 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('5mlj8ae9gt', 'Pump anklen frem og tilbage', 'Stå på ét ben. Hop frem og tilbage over en streg konsekutivt på samme fod. Fokus på hurtig ankelbevægelse og minimal kontakttid. Træner ankelstyrke og koordination.', 'fys', NULL, '["plyometrik"]', '[]', 5, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('rq6g2camse', 'Pump anklen sidevejs', 'Stå på ét ben. Hop sidelæns frem og tilbage over en streg konsekutivt på samme fod. Hurtig ankelbevægelse sidelæns. Træner lateral ankelstabilitet og reaktionskraft.', 'fys', NULL, '["plyometrik"]', '[]', 5, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('5hyxx0vhmx', 'Lang hop, backpedal tilabge', 'Lav et langt hop fremad på samlede ben – så langt som muligt. Løb straks bagud (backpedal) til startpunkt. 10 gentagelser. Kombinerer eksplosivt hop med hurtig retningsændring.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ow1nbokp4x', 'Boxjump bounce fremad', 'Stå på en boks. Hop ned på gulvet og sæt straks af til et langt hop fremad. 10 gentagelser. Kombinerer reaktivt nedhop med eksplosivt fremadgående hop. Simulerer angrebsafsæt.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, 'Land på forfoden!', NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('qifgo0du18', '3 hop på samlede, kontrolleret', '3 lange hop fremad på samlede ben – non-konsekutive med pause mellem hvert hop. Fokus på maksimal længde og kontrolleret landing. 10 gentagelser. Grundlæggende eksplosivitetsøvelse.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('lk6z6gfvaz', '3 hop på samlede, bounce', '3 lange konsekutive hop fremad på samlede ben – ingen pause. Hurtig og elastisk afsætning. Fokus på at holde tempoet oppe igennem alle 3 hop. Svarende til 3-skridtsbevægelse i håndbold.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, 'Land på forfoden! Evt efter nedhop fra boks', NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('y8qyfm66z3', '3 hop på samlede, bounce + eksplosion', '3 konsekutive lange hop på samlede ben efterfulgt af et kort sprint. Kombinerer plyometrisk hop med eksplosivt accelerationssprint. Simulerer angrebssituationen.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, 'Land på forfoden! Evt efter nedhop fra boks', NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('1iml2wycme', '3 lange og høje hop', '3 konsekutive hop – skiftevis langt hop og højt hop. Fokus på at maksimere enten længden eller højden. Træner variabel hopkraft og lufttid.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('6f631s6mx6', 'Lange hink', '10 lange hink på ét ben konsekutivt. Skift ben og gentag. Fokus på maksimal afstand pr. hink. Træner enbensstyrke og eksplosiv hoppekraft i én-benet afsæt.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 5, NULL, 'https://www.instagram.com/p/DMEyzmLJTA5/', 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('bhz1612uy8', 'Sidehop med sprint', 'Langt hop sidelæns på ét ben. Land kontrolleret på ét ben og hold positionen. 10 x 2 gentagelser. Fokus på landing og stabilitet. Forbereder til fintens sideretningsskift.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('t9wbk2zwrj', 'Eksplosive sidehops', 'Sidehop på ét ben, land på det yderste ben. Kort mellemhop og gentag. Hurtigere og mere eksplosiv end kontrolleret version. Simulerer den eksplosive del af en finteudførelse.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('7lstm9uhbx', 'Skaterhops fremad', 'Skaterhops fremad – non-konsekutive med kontrolleret landing. Fokus på højde og afstand. Land på ét ben og hold positionen. 20 gentagelser. Kombinerer lateral og fremadgående kraft.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('bg3xw2bmw5', 'Sidehop, hop med sprint', 'Langt sidestep, hurtigt hop fremad, land på samlet, kort sprint. Kombinationsøvelse der simulerer angrebets retningsskift: sidelæns finte efterfulgt af fremadrettet acceleration.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('n88pypsfl3', 'Sidesteps med sprint', '3 sidestep hop på samme fod over hække, efterfulgt af et kort sprint fremad. Simulerer 3-skridtsfinten med efterfølgende angrebsgennembrud.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, NULL, 'https://www.instagram.com/reel/DMjA5JuM02b/?igsh=Z2p0bmoxZnZwd3Fv', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('0yot46nzlb', 'Sprint fra knælende', 'Sid på ét knæ (starthugger-stilling). Sæt eksplosivt af til et 5-10 meter sprint. 10 gentagelser. Træner eksplosivt ankelskub og hurtig startaccelerations, svarende til opstarten fra lav position i forsvar.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 0, 'siddende på knæ kan både være mde front eller med siden til', 'https://www.instagram.com/reel/DMjA5JuM02b/?igsh=Z2p0bmoxZnZwd3Fv', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('1p3t6lraan', 'Hink: Små hink', 'Hinkerulle med lille mellemhink i hvert felt. Husk begge ben. Koordinationsøvelse der træner rytme, fodkoordination og hurtige ben.', 'fys', NULL, '["plyometrik","hurtighed"]', '[]', 5, 'Brug felter i valbyhallen eller stiger', NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('odwybfevc4', 'Hink: Frem og tilbage', 'Hink hvor der hoppes to felter frem, derefter et felt tilbage – konsekutivt. Træner rytme, retningsskift i hinken og koordination.', 'fys', NULL, '["plyometrik","hurtighed"]', '[]', 5, 'Brug felter i valbyhallen eller stiger', NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('4kqoxrgfsf', 'Hink: Ind og ud', 'Hink hvor man for hver andet felt lander inde i feltet, og hver andet udenfor feltet. Lateral koordinationsøvelse på hinkerulle.', 'fys', NULL, '["plyometrik","hurtighed"]', '[]', 5, 'Brug felter i valbyhallen eller stiger', NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('hdwh81k1tl', 'Hink: Lange hink', 'Med tilløb hopper man over to felter – lander kun i hvert andet felt. Træner kraftfuld afsætning og lang airtime i hink.', 'fys', NULL, '["plyometrik","hurtighed"]', '[]', 5, 'Brug felter i valbyhallen eller stiger', NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('rj9y724t9c', 'Bane: 3 skridtsforberedelse - samlede ben', 'Bane med 3 samlede hop, derefter eksplosivt sidestep til yderste ben, 3 samlede hop igen osv. Forbereder 3-skridtsbevægelsens rytme på samlede afsæt.', 'fys', NULL, '["plyometrik","finter"]', '[]', 0, NULL, 'https://www.instagram.com/p/DK_aq74Mdmn/', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('nfgbeky6ih', '5 bouncehop fremad på samlet', 'Spillerne stiller sig op og hopper fremad med små, hurtige hop på begge ben samtidigt, hvor kroppen drejer lidt fra side til side under hoppene. De udfører 5 hop i streg og lander kontrolleret efter den femte hop. Øvelsen træner eksplosiv kraft i benene, hurtighed og koordination, samtidig med at den forbedrer balancen og kropskontrol. Øvelsen kan gentages flere gange med kort pause mellem serierne.', 'fys', NULL, '["plyometrik","hurtighed","eksplosion"]', '[]', 5, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('egx3t3cplc', 'Bane: Skaterhops med hække', 'Sidestep til yderste ben, hop op på/over lille hæk på yderste ben. Bane med flere hække. Kombinerer lateral bevægelse med eksplosivt enbenshot. Træner sideoprulning.', 'fys', NULL, '["plyometrik","hurtighed","eksplosion"]', '[]', 0, 'Hurtigt og langt sidestep. Ok at lige finde balancen inden ophop', 'https://www.instagram.com/reel/DOzHcYcEk7z/?igsh=MnFyaTN4Y2xndjdy', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('kb6qwyzz31', 'Hink med sidestep', '6 hink på samme ben, efterfulgt af eksplosivt sidestep til yderste ben. Gentag med omvendt retning. Evt. over hæk. Kombinerer vertikal og lateral kraft.', 'fys', NULL, '["plyometrik","hurtighed","eksplosion"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ovulgpfoh6', 'Bane: 3 skridtsforberedelse - hink', '3 hink på samme ben, sidestep til yderste, 3 hink osv. Variation med hink i stedet for samlede hop. Forbereder hoppebevægelsens rytme til finterne.', 'fys', NULL, '["plyometrik","finter"]', '[]', 0, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('g446tw1ea2', 'Bane: 3 skridtsforberedelse -eksplosive hink', '3 hink på samme ben, 1 hink på modsatte (eksplosivt), 1 hink tilbage igen, sidestep. Avanceret baneøvelse der kombinerer rytmeskift og eksplosive hop.', 'fys', NULL, '["plyometrik","hurtighed","eksplosion"]', '[]', 0, NULL, 'https://www.instagram.com/p/DKoRAn6tA7W/', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('y7bcw7qdc1', 'Hop fra siddende med sideafsæt og sprint', 'Sid på bænk. 3 konsekutive hop på samlet til en markering. Derefter eksplosivt sidestep og kort sprint. Kombinationsøvelse der starter fra hvile og ender i fuld fart.', 'fys', NULL, '["plyometrik","hurtighed","eksplosion"]', '[]', 5, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('80cp9u32mo', 'Hop over hæk med sideafsæt og sprint', 'Hop over en hæk med samlede ben, land kontrolleret. Derefter hurtigt sidestep og sprint. Simulerer angrebets sideudvikling efter en kontrolleret landing.', 'fys', NULL, '["plyometrik","hurtighed","eksplosion"]', '[]', 0, NULL, 'https://www.instagram.com/reel/DMjA5JuM02b/?igsh=Z2p0bmoxZnZwd3Fv', 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('etrbo03qxl', 'Nedhop med 3 skridt', 'Hop ned fra en boks/bænk på samlede ben. Land og lav straks en treskridtsfinte. Kombinerer nedhop med angrebsbevægelse. Grundlæggende kombinationsøvelse.', 'fys', NULL, '["plyometrik","finter"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('o7gbsrtyzq', 'Nedhop med finte modsat skudarm', 'Hop ned fra boks og lav en fintebevægelse med overslag (1. div. finte) til den side der er modsat skudarmen. Øver den avancerede finte der narrer forsvar.', 'fys', NULL, '["plyometrik","finter"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('c19l9t6vqj', 'Nedhop med omvendt 3 skridt', 'Hop ned fra boks og lav treskridtsfinten til den ''forkerte'' side – starter samme fod som normalt men ender modsat. Uventet fintebevægelse der forvirrer forsvar.', 'fys', NULL, '["plyometrik","finter"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('w1ubiex2fe', 'Armbøjninger', 'Armstrækkere (push-ups): Ligge på maven med hænderne skulderbredde fra hinanden. Sæt ned til brystet nær gulvet og stræk armene. Fokus på lige krop. Træner bryst, skuldre og triceps.', 'fys', NULL, '["styrke"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('9divgq4zc4', 'Rygbøjninger', 'Lig på maven med hænderne bag nakken eller langs kroppen. Løft overkroppen fra gulvet ved at spænde rygmusklerne. Hold kort og sænk kontrolleret. Træner de nedre ryg- og rygmuskler.', 'fys', NULL, '["styrke"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('a38jj92f4u', 'Reaktionsøvelse', 'Par eller grupper: Reagér på signal (lyd, syn eller berøring) med en bestemt bevægelse. F.eks. grib en bold, rejs dig fra siddende eller sprint til markering. Kan varieres frit. Træner reaktionstid.', 'fys', NULL, '["styrke"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('7k8f3zhb2k', 'Mavebøjninger', 'Ligge på ryggen med bøjede knæ. Løft overkroppen mod knæene, hold kort og sænk kontrolleret. Fokus på at spænde mavemusklerne aktivt. Basis core-styrkeøvelse.', 'fys', NULL, '["styrke"]', '[]', 5, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('d7s2le4aq3', 'Lunges', 'Stå oprejst. Tag et stort skridt frem og sænk bageste knæ mod gulvet. Rejs dig og saml. Skift ben. Fokus på oprejst ryg og at det fremre knæ ikke går forbi tåspidserne. Træner quadriceps, baglår og hofte.', 'fys', NULL, '["styrke"]', '[]', 0, NULL, NULL, 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('bfspnwjhj8', 'Planken', 'Lig i pushup-position på underarme og tæer. Hold kroppen rank som en planke – ingen sænkning af hoften. Hold i 20-60 sekunder. Evt. med en makker der hopper let over spilleren fra side til side. Træner core og stabilitet.', 'fys', NULL, '["styrke"]', '[]', 0, NULL, NULL, 4, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('sz9vb1qk5p', 'Frøen', 'Længdehop på alle fire – som en frø. Hænderne og fødderne i gulvet, hop fremad og land på hænder og fødder samtidigt. Eksplosivt og kreativt hop der træner coordinationsevne og armstyrke.', 'fys', NULL, '["styrke","plyometrik","eksplosion","opvarmning"]', '[]', 1, 'den er svær. med god.', 'https://www.instagram.com/reel/DKh5OWetYFF/?igsh=czZibzFvbGhzYnpz', 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('leijx9rl68', 'Avancerede mavebøjninger', '2 og 2: Spiller 1 ligger med hovedet mellem spiller 2''s fødder (ryg mod gulv). Spiller 2 holder spiller 1 i fødderne og spiller 1 laver mavebøjninger op og lægger sig kontrolleret tilbage. Intensiverer maveøvelsen.', 'fys', NULL, '["styrke"]', '[]', 0, NULL, 'https://www.instagram.com/reel/DJ9PkajNFJU/?igsh=ZWNmZG9zd2doejE0', 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('ch0njll5k7', 'Trillebør', '2 og 2: Spiller 1 går på hænderne mens spiller 2 holder ankled oppe. Gå fremad på hænderne til markering og skift. Klassisk styrkeøvelse der træner arm-, skulder- og corestyrke.', 'fys', NULL, '["styrke"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('bgfv5dh7panmms5vyre', 'hop ned fra bænk, land på samlet, og hop højt', 'Spillerne står på en lav bænk, hopper ned og lander på begge ben samtidigt med bøjede knæ. Herefter hopper de straks så højt som muligt op i luften. Øvelsen træner eksplosiv kraft i benene, kropskontrol ved landing og hurtig afgangskraft. Gentag 8-10 gange per serie.', 'fys', NULL, '["plyometrik"]', '[]', 0, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('1qqjz3wgnfhmmlq0w72', '8 x længdehop på et ben fra stilstand', 'Spring og land på samme ben. 8 gentagelser per ben. Træner eksplosiv enbensstyrke og landing.', 'fys', NULL, '["plyometrik","eksplosion"]', '[]', 3, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('qrfnvtj3v4mmomo6cy', 'Skubbekamp med siden til på alle 4', 'To spillere stiller sig overfor hinanden på alle 4, med siden til mod hinanden. På trænersignal skubber de mod hinanden med hoften og skuldrene for at tvinge modstanderen væk fra sin position. Øvelsen træner kernestabilitet, balance og fysisk styrke.', 'fys', NULL, '["opvarmning","styrke"]', '[]', 0, NULL, 'https://www.instagram.com/reel/DTv9yxgEUhu/?igsh=NHNlMXQ1a3hramJh', 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('a1ewqvkgp7hmmomn6bh', 'Skubbekamp med siden til', 'To spillere står vendt mod hinanden med siden til. De placerer deres hånd mod hinandens skulder eller hofter og skubber hinanden uden at løfte fødderne fra jorden. På kommando skifter de hvilken side, der skal være mod hinanden. Øvelsen træner balanceevne, kropskontrol og styrke i benene.', 'fys', NULL, '["opvarmning","styrke"]', '[]', 0, NULL, 'https://www.instagram.com/reel/DTv9yxgEUhu/?igsh=NHNlMXQ1a3hramJh', 2, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('rzxw00v7xpmmw7p7f4', 'Lange hop på samlet x 6', 'Spillerne stiller sig op på en linje og udfører 6 lange hop i træk ved at springe så langt som muligt fra samlede, mens de lander på begge ben samtidigt hver gang. Øvelsen træner eksplosiv kraft i benene, koordination og balance, som er vigtig for springarbejde i håndbold. Det er vigtigt, at børnene fokuserer på en stabil landing efter hvert hop for at undgå skader og forbedre deres spring- og kastekraft.', 'fys', NULL, '["plyometrik"]', '[]', 5, NULL, NULL, 3, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('cad8y01rpqdmmwe0jbf', 'Stafet: hop keglen frem (frøhop)', 'Spillerne deles op i hold. Første spiller hopper så langt som muligt på begge ben, ligger kegle, spurter tilbage. Næste spiller spurter ud til kegle, samler den op, og hopper så langt hun kan. Ligger keglen. Forfra. Først til markør vinder', 'fys', NULL, '["plyometrik","opvarmning"]', '[]', 4, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('fkyspx2tyrmmwfmeje', 'Højt hop, kort sprint x 5', 'Spillerne stiller sig på en linje og laver først et højt hop, hvorefter de straks sprinter 5 meter fremad så hurtigt de kan. Øvelsen gentages flere gange med kort pause mellem hver gang. Derigennem trænes eksplosiv kraft i benene, hurtig acceleration og evnen til at skifte fra lodret til horisontalt bevægelse – færdigheder der er vigtige både ved skud og ved hurtigt at løbe på position under kampen.', 'fys', NULL, '["plyometrik"]', '[]', 5, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('tjexxj1ur7mmwfoxpn', 'Kapløb 10m', 'Spillerne stiller sig op i en linje ved startstregen og løber så hurtigt som muligt 10 meter til mållinjen, hvor de skal stoppe kontrolleret. Øvelsen gentages flere gange, gerne som konkurrencer mellem små grupper, så børnene bliver motiveret til at løbe deres allerbedste. Kapløbet træner eksplosiv kraft i benene, acceleration og hurtighed – kvaliteter der er vigtige for at komme først til bolden og være hurtig i spillet. Det er også en sjov måde at varme op på samtidig med, at man udvikler børnenes fysiske præstationer.', 'fys', NULL, '["plyometrik"]', '[]', 4, NULL, NULL, 5, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');
INSERT OR IGNORE INTO exercises (id, name, description, catalog, category, tags, age_groups, stars, variants, link, default_mins, image_r2_key, image_url, created_at, updated_at) VALUES ('9f93ngvvg0bmnd62kiq', 'Kapløb forlæns og baglæns 10 m sprint og retur', ' 10 m sprint og retur. Halvvejs er der en kegle, ved den skal man vende og løbe baglæns', 'fys', NULL, '["hurtighed","plyometrik"]', '[]', 0, NULL, 'https://www.instagram.com/reel/DS3R8oWDj0D/?igsh=bmMyc3psY2drMTN4', 10, NULL, NULL, '2026-04-14T00:00:00.000Z', '2026-04-14T00:00:00.000Z');